/**
 * This will get the average width of a character.
 *
 * @return The width of the character.
 */
public float getAverageCharacterWidth() {
    float average = 0;
    float totalWidths = 0;
    float characterCount = 0;
    for (org.apache.fontbox.afm.CharMetric metric : charMetrics) {
        if (metric.getWx() > 0) {
            totalWidths += metric.getWx();
            characterCount += 1;
        }
    }
    if (totalWidths > 0) {
        average = totalWidths / characterCount;
    }
    return average;
}

/**
 * This will get the width of a character.
 *
 * @param name
 * 		The character to get the width for.
 * @return The width of the character.
 */
public float getCharacterHeight(java.lang.String name) {
    float result = 0;
    org.apache.fontbox.afm.CharMetric metric = charMetricsMap.get(name);
    if (metric != null) {
        result = metric.getWy();
        if (java.lang.Float.compare(result, 0) == 0) {
            result = metric.getBoundingBox().getHeight();
        }
    }
    return result;
}

/**
 * This will get the width of a character.
 *
 * @param name
 * 		The character to get the width for.
 * @return The width of the character.
 */
public float getCharacterWidth(java.lang.String name) {
    float result = 0;
    org.apache.fontbox.afm.CharMetric metric = charMetricsMap.get(name);
    if (metric != null) {
        result = metric.getWx();
    }
    return result;
}

