/**
 * Returns the Type 2 charstring for the given CID.
 *
 * @param cid
 * 		CID
 * @throws IOException
 * 		if the charstring could not be read
 */
@java.lang.Override
public org.apache.fontbox.cff.CIDKeyedType2CharString getType2CharString(int cid) throws java.io.IOException {
    org.apache.fontbox.cff.CIDKeyedType2CharString type2 = charStringCache.get(cid);
    if (type2 == null) {
        int gid = getCharset().getGIDForCID(cid);
        byte[] bytes = charStrings[gid];
        if (bytes == null) {
            bytes = charStrings[0];// .notdef

        }
        java.util.List<java.lang.Object> type2seq = getParser().parse(bytes, globalSubrIndex, getLocalSubrIndex(gid));
        type2 = new org.apache.fontbox.cff.CIDKeyedType2CharString(reader, getName(), cid, gid, type2seq, getDefaultWidthX(gid), getNominalWidthX(gid));
        charStringCache.put(cid, type2);
    }
    return type2;
}

