/**
 * Parse CFF font using byte array, also passing in a byte source for future use.
 *
 * @param bytes
 * 		source bytes
 * @param source
 * 		source to re-read bytes from in the future
 * @return the parsed CFF fonts
 * @throws IOException
 * 		If there is an error reading from the stream
 */
public java.util.List<org.apache.fontbox.cff.CFFFont> parse(byte[] bytes, org.apache.fontbox.cff.CFFParser.ByteSource source) throws java.io.IOException {
    // TODO do we need to store the source data of the font? It isn't used at all
    this.source = source;
    return parse(new org.apache.fontbox.cff.DataInputByteArray(bytes));
}

/**
 * Parse CFF font using a RandomAccessRead as input.
 *
 * @param randomAccessRead
 * 		the source to be parsed
 * @return the parsed CFF fonts
 * @throws IOException
 * 		If there is an error reading from the stream
 */
public java.util.List<org.apache.fontbox.cff.CFFFont> parse(org.apache.pdfbox.io.RandomAccessRead randomAccessRead) throws java.io.IOException {
    // TODO do we need to store the source data of the font? It isn't used at all
    byte[] bytes = new byte[((int) (randomAccessRead.length()))];
    randomAccessRead.seek(0);
    int remainingBytes = bytes.length;
    int amountRead;
    while ((amountRead = randomAccessRead.read(bytes, bytes.length - remainingBytes, remainingBytes)) > 0) {
        remainingBytes -= amountRead;
    } 
    randomAccessRead.seek(0);
    this.source = new org.apache.fontbox.cff.CFFParser.CFFBytesource(bytes);
    return parse(new org.apache.fontbox.cff.DataInputRandomAccessRead(randomAccessRead));
}

