/**
 * Returns the GID for the given PostScript glyph name.
 *
 * @param name
 * 		a PostScript glyph name.
 * @return GID
 */
public int nameToGID(java.lang.String name) {
    // some fonts have glyphs beyond their encoding, so we look up by charset SID
    int sid = getCharset().getSID(name);
    return getCharset().getGIDForSID(sid);
}

/**
 * Peeks one single unsigned byte from the buffer.
 *
 * @param offset
 * 		offset to the byte to be peeked
 * @return the unsigned byte as int
 * @throws IOException
 * 		if an error occurs during reading
 */
@java.lang.Override
public int peekUnsignedByte(int offset) throws java.io.IOException {
    if (offset < 0) {
        throw new java.io.IOException("offset is negative");
    }
    if ((bufferPosition + offset) >= inputBuffer.length) {
        throw new java.io.IOException((("Offset position is out of range " + (bufferPosition + offset)) + " >= ") + inputBuffer.length);
    }
    return inputBuffer[bufferPosition + offset] & 0xff;
}

/**
 * Read one single byte from the buffer.
 *
 * @return the byte
 * @throws IOException
 * 		if an error occurs during reading
 */
@java.lang.Override
public byte readByte() throws java.io.IOException {
    if (!hasRemaining()) {
        throw new java.io.IOException("End off buffer reached");
    }
    return inputBuffer[bufferPosition++];
}

/**
 * Read a number of single byte values from the buffer.
 *
 * @param length
 * 		the number of bytes to be read
 * @return an array with containing the bytes from the buffer
 * @throws IOException
 * 		if an error occurs during reading
 */
@java.lang.Override
public byte[] readBytes(int length) throws java.io.IOException {
    if (length < 0) {
        throw new java.io.IOException("length is negative");
    }
    if ((inputBuffer.length - bufferPosition) < length) {
        throw new java.io.IOException("Premature end of buffer reached");
    }
    byte[] bytes = new byte[length];
    java.lang.System.arraycopy(inputBuffer, bufferPosition, bytes, 0, length);
    bufferPosition += length;
    return bytes;
}

/**
 * Read one single unsigned byte from the buffer.
 *
 * @return the unsigned byte as int
 * @throws IOException
 * 		if an error occurs during reading
 */
@java.lang.Override
public int readUnsignedByte() throws java.io.IOException {
    if (!hasRemaining()) {
        throw new java.io.IOException("End off buffer reached");
    }
    return inputBuffer[bufferPosition++] & 0xff;
}

/**
 * Sets the current position to the given value.
 *
 * @param position
 * 		the given position
 * @throws IOException
 * 		if the new position ist out of range
 */
@java.lang.Override
public void setPosition(int position) throws java.io.IOException {
    if (position < 0) {
        throw new java.io.IOException("position is negative");
    }
    if (position >= inputBuffer.length) {
        throw new java.io.IOException((("New position is out of range " + position) + " >= ") + inputBuffer.length);
    }
    bufferPosition = position;
}

/**
 * Peeks one single unsigned byte from the buffer.
 *
 * @param offset
 * 		offset to the byte to be peeked, must be 0 &le; offset.
 * @return the unsigned byte as int.
 * @throws IOException
 * 		when the offset is negative or beyond end_of_buffer, or when the
 * 		underlying buffer has already been closed.
 */
@java.lang.Override
public int peekUnsignedByte(int offset) throws java.io.IOException {
    if (offset < 0) {
        throw new java.io.IOException("offset is negative");
    }
    if (offset == 0) {
        return randomAccessRead.peek();
    }
    long currentPosition = randomAccessRead.getPosition();
    if ((currentPosition + offset) >= randomAccessRead.length()) {
        throw new java.io.IOException((("Offset position is out of range " + (currentPosition + offset)) + " >= ") + randomAccessRead.length());
    }
    randomAccessRead.seek(currentPosition + offset);
    int peekValue = randomAccessRead.read();
    randomAccessRead.seek(currentPosition);
    return peekValue;
}

/**
 * Read one single byte from the buffer.
 *
 * @return the byte.
 * @throws IOException
 * 		when there are no bytes to read or when the underlying buffer has already
 * 		been closed.
 */
@java.lang.Override
public byte readByte() throws java.io.IOException {
    if (!hasRemaining()) {
        throw new java.io.IOException("End of buffer reached!");
    }
    return ((byte) (randomAccessRead.read()));
}

/**
 * Read a number of single byte values from the buffer.<br>
 * Note: when <code>readBytes(5)</code> is called, but there are only 3 bytes available, the
 * caller gets an IOException, not the 3 bytes!
 *
 * @param length
 * 		the number of bytes to be read, must be 0 &le; length.
 * @return an array with containing the bytes from the buffer.
 * @throws IOException
 * 		when there are less than <code>length</code> bytes available or when the
 * 		underlying buffer has already been closed.
 */
@java.lang.Override
public byte[] readBytes(int length) throws java.io.IOException {
    if (length < 0) {
        throw new java.io.IOException("length is negative");
    }
    byte[] bytes = new byte[length];
    randomAccessRead.readFully(bytes);
    return bytes;
}

/**
 * Read one single unsigned byte from the buffer.
 *
 * @return the unsigned byte as int.
 * @throws IOException
 * 		when there are no bytes to read or when the underlying buffer has been
 * 		already closed.
 */
@java.lang.Override
public int readUnsignedByte() throws java.io.IOException {
    if (!hasRemaining()) {
        throw new java.io.IOException("End of buffer reached!");
    }
    return randomAccessRead.read();
}

/**
 * Sets the current <i>absolute</i> position to the given value. You <i>cannot</i> use
 * <code>setPosition(-20)</code> to move 20 bytes back!
 *
 * @param position
 * 		the given position, must be 0 &le; position &lt; length.
 * @throws IOException
 * 		if the new position is out of range or when the underlying buffer has
 * 		already been closed.
 */
@java.lang.Override
public void setPosition(int position) throws java.io.IOException {
    if (position < 0) {
        throw new java.io.IOException("position is negative");
    }
    if (position >= randomAccessRead.length()) {
        throw new java.io.IOException((("New position is out of range " + position) + " >= ") + randomAccessRead.length());
    }
    randomAccessRead.seek(position);
}

