/**
 * Reads a character code from a string in the content stream.
 * <p>
 * See "CMap Mapping" and "Handling Undefined Characters" in PDF32000 for more details.
 *
 * @param in
 * 		string stream
 * @return character code
 * @throws IOException
 * 		if there was an error reading the stream or CMap
 */
public int readCode(java.io.InputStream in) throws java.io.IOException {
    byte[] bytes = new byte[maxCodeLength];
    in.read(bytes, 0, minCodeLength);
    in.mark(maxCodeLength);
    for (int i = minCodeLength - 1; i < maxCodeLength; i++) {
        final int byteCount = i + 1;
        if (codespaceRanges.stream().anyMatch(r -> r.isFullMatch(bytes, byteCount))) {
            return org.apache.fontbox.cmap.CMap.toInt(bytes, byteCount);
        }
        if (byteCount < maxCodeLength) {
            bytes[byteCount] = ((byte) (in.read()));
        }
    }
    if (org.apache.fontbox.cmap.CMap.LOG.isWarnEnabled()) {
        java.lang.StringBuilder sb = new java.lang.StringBuilder();
        for (int i = 0; i < maxCodeLength; ++i) {
            sb.append(java.lang.String.format("0x%02X (%04o) ", bytes[i], bytes[i]));
        }
        org.apache.fontbox.cmap.CMap.LOG.warn("Invalid character code sequence {} in CMap {}", sb, cmapName);
    }
    // PDFBOX-4811 reposition to where we were after initial read
    if (in.markSupported()) {
        in.reset();
    } else {
        org.apache.fontbox.cmap.CMap.LOG.warn("mark() and reset() not supported, {} bytes have been skipped", maxCodeLength - 1);
    }
    return org.apache.fontbox.cmap.CMap.toInt(bytes, minCodeLength);// Adobe Reader behavior

}

/**
 * Returns the CID for the given character code.
 *
 * @param code
 * 		character code as byte array
 * @return CID
 */
public int toCID(byte[] code) {
    if (((!hasCIDMappings()) || (code.length < minCidLength)) || (code.length > maxCidLength)) {
        return 0;
    }
    java.lang.Integer cid = null;
    java.util.Map<java.lang.Integer, java.lang.Integer> codeToCidMap = codeToCid.get(code.length);
    if (codeToCidMap != null) {
        cid = codeToCidMap.get(org.apache.fontbox.cmap.CMap.toInt(code));
    }
    return cid != null ? cid : toCIDFromRanges(code);
}

/**
 * Returns the CID for the given character code.
 *
 * This method exists for convenience. It may return false values as the origin byte length of the input value is
 * unknown and the mapping for some input values aren't unique. <br>
 * Example:<br>
 * The two byte value 0x00, 0x65 maps to 0x20 <br>
 * An input value of 0x65 always returns 0x20 even if the value has an origin byte length of 1.
 *
 * @param code
 * 		character code
 * @return CID
 */
public int toCID(int code) {
    if (!hasCIDMappings()) {
        return 0;
    }
    int cid = 0;
    int length = minCidLength;
    while ((cid == 0) && (length <= maxCidLength)) {
        cid = toCID(code, length++);
    } 
    return cid;
}

/**
 * Returns the CID for the given character code.
 *
 * @param code
 * 		character code
 * @param length
 * 		the origin byte length of the code
 * @return CID
 */
public int toCID(int code, int length) {
    if (((!hasCIDMappings()) || (length < minCidLength)) || (length > maxCidLength)) {
        return 0;
    }
    java.lang.Integer cid = null;
    java.util.Map<java.lang.Integer, java.lang.Integer> codeToCidMap = codeToCid.get(length);
    if (codeToCidMap != null) {
        cid = codeToCidMap.get(code);
    }
    return cid != null ? cid : toCIDFromRanges(code, length);
}

/**
 * Returns the sequence of Unicode characters for the given character code.
 *
 * This method exists for convenience. It may return false values as the origin byte length of the input value is
 * unknown and the mapping for some input values aren't unique. <br>
 * Example:<br>
 * The two byte value 0x00, 0x65 maps to 0x20 <br>
 * An input value of 0x65 always returns 0x20 even if the value has an origin byte length of 1.
 *
 * @param code
 * 		character code
 * @return Unicode characters (may be more than one, e.g "fi" ligature)
 */
public java.lang.String toUnicode(int code) {
    java.lang.String unicode = (code < 256) ? toUnicode(code, 1) : null;
    if (unicode == null) {
        if (code <= 0xffff) {
            return toUnicode(code, 2);
        }
        if (code <= 0xffffff) {
            return toUnicode(code, 3);
        }
        return toUnicode(code, 4);
    }
    return unicode;
}

/**
 * Returns the sequence of Unicode characters for the given character code.
 *
 * @param code
 * 		character code
 * @param length
 * 		code length
 * @return Unicode characters (may be more than one, e.g "fi" ligature)
 */
public java.lang.String toUnicode(int code, int length) {
    if (length == 1) {
        return charToUnicodeOneByte.get(code);
    }
    if (length == 2) {
        return charToUnicodeTwoBytes.get(code);
    }
    return charToUnicodeMoreBytes.get(code);
}

/**
 * This will parse the stream and create a cmap object.
 *
 * @param randomAccessRead
 * 		the source of the CMap to be parsed.
 * @return The parsed source as a java object, never null.
 * @throws IOException
 * 		If there is an error parsing the data.
 */
public org.apache.fontbox.cmap.CMap parse(org.apache.pdfbox.io.RandomAccessRead randomAccessRead) throws java.io.IOException {
    org.apache.fontbox.cmap.CMap result = new org.apache.fontbox.cmap.CMap();
    java.lang.Object previousToken = null;
    java.lang.Object token = parseNextToken(randomAccessRead);
    while (token != null) {
        if (token instanceof org.apache.fontbox.cmap.CMapParser.Operator) {
            org.apache.fontbox.cmap.CMapParser.Operator op = ((org.apache.fontbox.cmap.CMapParser.Operator) (token));
            if (op.op.equals("endcmap")) {
                // end of CMap reached, stop reading as there isn't any interesting info anymore
                break;
            }
            if (op.op.equals("usecmap") && (previousToken instanceof org.apache.fontbox.cmap.CMapParser.LiteralName)) {
                parseUsecmap(((org.apache.fontbox.cmap.CMapParser.LiteralName) (previousToken)), result);
            } else if (previousToken instanceof java.lang.Number) {
                if (op.op.equals("begincodespacerange")) {
                    parseBegincodespacerange(((java.lang.Number) (previousToken)), randomAccessRead, result);
                } else if (op.op.equals("beginbfchar")) {
                    parseBeginbfchar(((java.lang.Number) (previousToken)), randomAccessRead, result);
                } else if (op.op.equals("beginbfrange")) {
                    parseBeginbfrange(((java.lang.Number) (previousToken)), randomAccessRead, result);
                } else if (op.op.equals("begincidchar")) {
                    parseBegincidchar(((java.lang.Number) (previousToken)), randomAccessRead, result);
                } else if (op.op.equals("begincidrange") && (previousToken instanceof java.lang.Integer)) {
                    parseBegincidrange(((java.lang.Integer) (previousToken)), randomAccessRead, result);
                }
            }
        } else if (token instanceof org.apache.fontbox.cmap.CMapParser.LiteralName) {
            parseLiteralName(((org.apache.fontbox.cmap.CMapParser.LiteralName) (token)), randomAccessRead, result);
        }
        previousToken = token;
        token = parseNextToken(randomAccessRead);
    } 
    return result;
}

/**
 * Returns true if the given number of code bytes match this codespace range.
 *
 * @param code
 * 		the code bytes to be matched
 * @param codeLen
 * 		the code length to be used for matching
 * @return true if the given number of code bytes match this codespace range
 */
public boolean isFullMatch(byte[] code, int codeLen) {
    // code must be the same length as the bounding codes
    if (codeLength != codeLen) {
        return false;
    }
    for (int i = 0; i < codeLength; i++) {
        int codeAsInt = code[i] & 0xff;
        if ((codeAsInt < start[i]) || (codeAsInt > end[i])) {
            return false;
        }
    }
    return true;
}

