/**
 * Returns all possible character codes for the given gid, or null if there is none.
 *
 * @param gid
 * 		glyph id
 * @return a list with all character codes the given gid maps to
 */
@java.lang.Override
public java.util.List<java.lang.Integer> getCharCodes(int gid) {
    int code = getCharCode(gid);
    if (code == (-1)) {
        return null;
    }
    java.util.List<java.lang.Integer> codes = null;
    if (code == java.lang.Integer.MIN_VALUE) {
        java.util.List<java.lang.Integer> mappedValues = glyphIdToCharacterCodeMultiple.get(gid);
        if (mappedValues != null) {
            codes = new java.util.ArrayList<>(mappedValues);
            // sort the list to provide a reliable order
            java.util.Collections.sort(codes);
        }
    } else {
        codes = java.util.Collections.singletonList(code);
    }
    return codes;
}

