/**
 * Returns the subtable, if any, for the given platform and encoding.
 *
 * @param platformId
 * 		the ID of the given platform
 * @param platformEncodingId
 * 		the ID of the given encoding
 * @return the subtable, if any, or null
 */
public org.apache.fontbox.ttf.CmapSubtable getSubtable(int platformId, int platformEncodingId) {
    for (org.apache.fontbox.ttf.CmapSubtable cmap : cmaps) {
        if ((cmap.getPlatformId() == platformId) && (cmap.getPlatformEncodingId() == platformEncodingId)) {
            return cmap;
        }
    }
    return null;
}

/**
 * {@inheritDoc }
 */
@java.lang.Override
public int getContourCount() {
    if (!resolved) {
        org.apache.fontbox.ttf.GlyfCompositeDescript.LOG.error("getContourCount called on unresolved GlyfCompositeDescript");
    }
    if (contourCount < 0) {
        org.apache.fontbox.ttf.GlyfCompositeComp c = components.get(components.size() - 1);
        org.apache.fontbox.ttf.GlyphDescription gd = descriptions.get(c.getGlyphIndex());
        if (gd == null) {
            org.apache.fontbox.ttf.GlyfCompositeDescript.LOG.error("missing glyph description for index {}", c.getGlyphIndex());
            contourCount = 0;
        } else {
            contourCount = c.getFirstContour() + gd.getContourCount();
        }
    }
    return contourCount;
}

/**
 * {@inheritDoc }
 */
@java.lang.Override
public int getEndPtOfContours(int i) {
    org.apache.fontbox.ttf.GlyfCompositeComp c = getCompositeCompEndPt(i);
    if (c != null) {
        org.apache.fontbox.ttf.GlyphDescription gd = descriptions.get(c.getGlyphIndex());
        return gd.getEndPtOfContours(i - c.getFirstContour()) + c.getFirstIndex();
    }
    return 0;
}

/**
 * {@inheritDoc }
 */
@java.lang.Override
public byte getFlags(int i) {
    org.apache.fontbox.ttf.GlyfCompositeComp c = getCompositeComp(i);
    if (c != null) {
        org.apache.fontbox.ttf.GlyphDescription gd = descriptions.get(c.getGlyphIndex());
        return gd.getFlags(i - c.getFirstIndex());
    }
    return 0;
}

/**
 * {@inheritDoc }
 */
@java.lang.Override
public int getPointCount() {
    if (!resolved) {
        org.apache.fontbox.ttf.GlyfCompositeDescript.LOG.error("getPointCount called on unresolved GlyfCompositeDescript");
    }
    if (pointCount < 0) {
        org.apache.fontbox.ttf.GlyfCompositeComp c = components.get(components.size() - 1);
        org.apache.fontbox.ttf.GlyphDescription gd = descriptions.get(c.getGlyphIndex());
        if (gd == null) {
            org.apache.fontbox.ttf.GlyfCompositeDescript.LOG.error("GlyphDescription for index {} is null, returning 0", c.getGlyphIndex());
            pointCount = 0;
        } else {
            pointCount = c.getFirstIndex() + gd.getPointCount();
        }
    }
    return pointCount;
}

