/**
 * Builds a new {@link GsubData} instance for given script tag. In contrast to neighbour {@link #getGsubData()}
 * method, this one does not try to find the first supported language and load GSUB data for it. Instead, it fetches
 * the data for the given {@code scriptTag} (if it's supported by the font) leaving the language unspecified. It
 * means that even after successful reading of GSUB data, the actual glyph substitution may not work if there is no
 * corresponding {@link org.apache.fontbox.ttf.gsub.GsubWorker} implementation for it.
 *
 * Note: This method performs searching on every invocation (no results are cached)
 *
 * @param scriptTag
 * 		a <a href="https://learn.microsoft.com/en-us/typography/opentype/spec/scripttags">script tag</a>
 * 		for which the data is needed
 * @return GSUB data for the given script or {@code null} if no such script in the font
 */
public org.apache.fontbox.ttf.model.GsubData getGsubData(java.lang.String scriptTag) {
    org.apache.fontbox.ttf.table.common.ScriptTable scriptTable = scriptList.get(scriptTag);
    if (scriptTable == null) {
        return null;
    }
    return new org.apache.fontbox.ttf.gsub.GlyphSubstitutionDataExtractor().getGsubData(scriptTag, scriptTable, featureListTable, lookupListTable);
}

/**
 * Apply glyph substitutions to the supplied gid. The applicable substitutions are determined by the
 * {@code scriptTags} which indicate the language of the gid, and by the list of {@code enabledFeatures}.
 *
 * To ensure that a single gid isn't mapped to multiple substitutions, subsequent invocations with the same gid will
 * return the same result as the first, regardless of script or enabled features.
 *
 * @param gid
 * 		GID
 * @param scriptTags
 * 		Script tags applicable to the gid (see {@link OpenTypeScript})
 * @param enabledFeatures
 * 		list of features to apply
 * @return the id of the glyph substitution
 */
public int getSubstitution(int gid, java.lang.String[] scriptTags, java.util.List<java.lang.String> enabledFeatures) {
    if (gid == (-1)) {
        return -1;
    }
    java.lang.Integer cached = lookupCache.get(gid);
    if (cached != null) {
        // Because script detection for indeterminate scripts (COMMON, INHERIT, etc.) depends on context,
        // it is possible to return a different substitution for the same input. However, we don't want that,
        // as we need a one-to-one mapping.
        return cached;
    }
    java.lang.String scriptTag = selectScriptTag(scriptTags);
    java.util.Collection<org.apache.fontbox.ttf.table.common.LangSysTable> langSysTables = getLangSysTables(scriptTag);
    java.util.List<org.apache.fontbox.ttf.table.common.FeatureRecord> featureRecords = getFeatureRecords(langSysTables, enabledFeatures);
    int sgid = gid;
    for (org.apache.fontbox.ttf.table.common.FeatureRecord featureRecord : featureRecords) {
        sgid = applyFeature(featureRecord, sgid);
    }
    lookupCache.put(gid, sgid);
    reverseLookup.put(sgid, gid);
    return sgid;
}

/**
 * For a substitute-gid (obtained from {@link #getSubstitution(int, String[], List)}),
 * retrieve the original gid.
 * <p>
 * Only gids previously substituted by this instance can be un-substituted.
 * If you are trying to unsubstitute before you substitute, something is wrong.
 *
 * @param sgid
 * 		Substitute GID
 * @return the original gid of a substitute-gid
 */
public int getUnsubstitution(int sgid) {
    java.lang.Integer gid = reverseLookup.get(sgid);
    if (gid == null) {
        org.apache.fontbox.ttf.GlyphSubstitutionTable.LOG.warn("Trying to un-substitute a never-before-seen gid: {}", sgid);
        return sgid;
    }
    return gid;
}

/**
 * Returns the advance width for the given GID.
 *
 * @param gid
 * 		GID
 * @return the advance width of the given GID
 */
public int getAdvanceWidth(int gid) {
    if (advanceWidth.length == 0) {
        return 250;
    }
    if (gid < numHMetrics) {
        return advanceWidth[gid];
    } else {
        // monospaced fonts may not have a width for every glyph
        // the last one is for subsequent glyphs
        return advanceWidth[advanceWidth.length - 1];
    }
}

/**
 * Returns the left side bearing for the given GID.
 *
 * @param gid
 * 		GID
 * @return the left side bearing of the given GID
 */
public int getLeftSideBearing(int gid) {
    if (leftSideBearing.length == 0) {
        return 0;
    }
    if (gid < numHMetrics) {
        return leftSideBearing[gid];
    } else {
        return nonHorizontalLeftSideBearing[gid - numHMetrics];
    }
}

/**
 * Obtain kerning adjustment for glyph pair {L,R}.
 *
 * @param l
 * 		left member of glyph pair
 * @param r
 * 		right member of glyph pair
 * @return a (possibly zero) kerning adjustment
 */
public int getKerning(int l, int r) {
    if (pairs == null) {
        org.apache.fontbox.ttf.KerningSubtable.LOG.warn("No kerning subtable data available due to an unsupported kerning subtable version");
        return 0;
    }
    return pairs.getKerning(l, r);
}

/**
 * Obtain kerning adjustments for GLYPHS sequence, where the
 * Nth returned adjustment is associated with the Nth glyph
 * and the succeeding non-zero glyph in the GLYPHS sequence.
 *
 * Kerning adjustments are returned in font design coordinates.
 *
 * @param glyphs
 * 		a (possibly empty) array of glyph identifiers
 * @return a (possibly empty) array of kerning adjustments
 */
public int[] getKerning(int[] glyphs) {
    int[] kerning = null;
    if (pairs != null) {
        int ng = glyphs.length;
        kerning = new int[ng];
        for (int i = 0; i < ng; ++i) {
            int l = glyphs[i];
            int r = -1;
            for (int k = i + 1; k < ng; ++k) {
                int g = glyphs[k];
                if (g >= 0) {
                    r = g;
                    break;
                }
            }
            kerning[i] = getKerning(l, r);
        }
    } else {
        org.apache.fontbox.ttf.KerningSubtable.LOG.warn("No kerning subtable data available due to an unsupported kerning subtable version");
    }
    return kerning;
}

/**
 * Obtain first subtable that supports horizontal kerning with specified cross stream.
 *
 * @param cross
 * 		true if requesting cross stream horizontal kerning
 * @return first matching subtable or null if none found
 */
public org.apache.fontbox.ttf.KerningSubtable getHorizontalKerningSubtable(boolean cross) {
    if (subtables != null) {
        for (org.apache.fontbox.ttf.KerningSubtable s : subtables) {
            if (s.isHorizontalKerning(cross)) {
                return s;
            }
        }
    }
    return null;
}

/**
 * Returns a name from the table, or null it it does not exist.
 *
 * @param nameId
 * 		Name ID from NameRecord constants.
 * @param platformId
 * 		Platform ID from NameRecord constants.
 * @param encodingId
 * 		Platform Encoding ID from NameRecord constants.
 * @param languageId
 * 		Language ID from NameRecord constants.
 * @return name, or null
 */
public java.lang.String getName(int nameId, int platformId, int encodingId, int languageId) {
    java.util.Map<java.lang.Integer, java.util.Map<java.lang.Integer, java.util.Map<java.lang.Integer, java.lang.String>>> platforms = lookupTable.get(nameId);
    if (platforms == null) {
        return null;
    }
    java.util.Map<java.lang.Integer, java.util.Map<java.lang.Integer, java.lang.String>> encodings = platforms.get(platformId);
    if (encodings == null) {
        return null;
    }
    java.util.Map<java.lang.Integer, java.lang.String> languages = encodings.get(encodingId);
    if (languages == null) {
        return null;
    }
    return languages.get(languageId);
}

