 * @return A TrueType font.
 * @throws IOException
 * 		If there is an error parsing the TrueType font.
 */
public org.apache.fontbox.ttf.TrueTypeFont parse(org.apache.pdfbox.io.RandomAccessRead randomAccessRead) throws java.io.IOException {
    org.apache.fontbox.ttf.RandomAccessReadDataStream dataStream = new org.apache.fontbox.ttf.RandomAccessReadDataStream(randomAccessRead);
    try  {
        return parse(dataStream);
    } catch (java.io.IOException ex) {
        // close only on error (source is still being accessed later)
        dataStream.close();
        throw ex;
    }
}

