    addCompoundReferences();
    java.util.Map<java.lang.Integer, java.lang.Integer> newToOld = new java.util.HashMap<>();
    int newGID = 0;
    for (int oldGID : glyphIds) {
        newToOld.put(newGID, oldGID);
        newGID++;
    }
    return newToOld;
}

