 */
public org.apache.fontbox.ttf.CmapLookup getUnicodeCmapLookup(boolean isStrict) throws java.io.IOException {
    org.apache.fontbox.ttf.CmapSubtable cmap = getUnicodeCmapImpl(isStrict);
    if (!enabledGsubFeatures.isEmpty()) {
        org.apache.fontbox.ttf.GlyphSubstitutionTable table = getGsub();
        if (table != null) {
            return new org.apache.fontbox.ttf.SubstitutingCmapLookup(cmap, table, java.util.Collections.unmodifiableList(enabledGsubFeatures));
        }
