/**
 * Returns the GID for the given PostScript name, if the "post" table is present.
 *
 * @param name
 * 		the PostScript name.
 * @return the GID for the given PostScript name
 * @throws IOException
 * 		if the font data could not be read
 */
public int nameToGID(java.lang.String name) throws java.io.IOException {
    // look up in 'post' table
    readPostScriptNames();
    if (postScriptNames != null) {
        java.lang.Integer gid = postScriptNames.get(name);
        if (((gid != null) && (gid > 0)) && (gid < getMaximumProfile().getNumGlyphs())) {
            return gid;
        }
    }
    // look up in 'cmap'
    int uni = parseUniName(name);
    if (uni > (-1)) {
        org.apache.fontbox.ttf.CmapLookup cmap = getUnicodeCmapLookup(false);
        return cmap.getGlyphId(uni);
    }
    // PDFBOX-5604: assume gnnnnn is a gid
    if (name.matches("g\\d+")) {
        return java.lang.Integer.parseInt(name.substring(1));
    }
    return 0;
}

/**
 * Tokenize a string into tokens.
 *
 * @param text
 * 		A string like "_66_71_71_74_79_70_"
 * @return A list of tokens like "_66_", "_71_71_", "74_79_70_". The "_" is sometimes missing at
the beginning or end, this has to be cleaned by the caller.
 */
public java.util.List<java.lang.String> tokenize(java.lang.String text) {
    java.util.List<java.lang.String> tokens = new java.util.ArrayList<>();
    java.util.regex.Matcher regexMatcher = regexExpression.matcher(text);
    int lastIndexOfPrevMatch = 0;
    // this is where the magic happens:
    // the regexp is used to find a matching pattern for substitution
    while (regexMatcher.find(lastIndexOfPrevMatch)) {
        int beginIndexOfNextMatch = regexMatcher.start();
        java.lang.String prevToken = text.substring(lastIndexOfPrevMatch, beginIndexOfNextMatch);
        if (!prevToken.isEmpty()) {
            tokens.add(prevToken);
        }
        java.lang.String currentMatch = regexMatcher.group();
        tokens.add(currentMatch);
        lastIndexOfPrevMatch = regexMatcher.end();
        if ((lastIndexOfPrevMatch < text.length()) && (text.charAt(lastIndexOfPrevMatch) != '_')) {
            // beause it is sometimes positioned after the "_", but it should be positioned
            // before the "_"
            --lastIndexOfPrevMatch;
        }
    } 
    java.lang.String tail = text.substring(lastIndexOfPrevMatch);
    if (!tail.isEmpty()) {
        tokens.add(tail);
    }
    return tokens;
}

@java.lang.Override
public java.util.List<java.util.List<java.lang.Integer>> split(java.util.List<java.lang.Integer> glyphIds) {
    java.lang.String originalGlyphsAsText = convertGlyphIdsToString(glyphIds);
    java.util.List<java.lang.String> tokens = compoundCharacterTokenizer.tokenize(originalGlyphsAsText);
    java.util.List<java.util.List<java.lang.Integer>> modifiedGlyphs = new java.util.ArrayList<>(tokens.size());
    tokens.forEach(token -> modifiedGlyphs.add(convertGlyphIdsToList(token)));
    return modifiedGlyphs;
}

/**
 * Unlike {@link #getGsubData(Map, FeatureListTable, LookupListTable)}, this method doesn't iterate over supported
 * {@link Language}'s searching for the first match with the scripts of the font. Instead, it unconditionally
 * creates {@link ScriptTableDetails} instance with language left {@linkplain Language#UNSPECIFIED unspecified}.
 *
 * @param scriptName
 * @param scriptTable
 * @param featureListTable
 * @param lookupListTable
 * @return {@link GsubData} instance built especially for the given {@code scriptName}
 */
public org.apache.fontbox.ttf.model.GsubData getGsubData(java.lang.String scriptName, org.apache.fontbox.ttf.table.common.ScriptTable scriptTable, org.apache.fontbox.ttf.table.common.FeatureListTable featureListTable, org.apache.fontbox.ttf.table.common.LookupListTable lookupListTable) {
    org.apache.fontbox.ttf.gsub.GlyphSubstitutionDataExtractor.ScriptTableDetails scriptTableDetails = new org.apache.fontbox.ttf.gsub.GlyphSubstitutionDataExtractor.ScriptTableDetails(org.apache.fontbox.ttf.model.Language.UNSPECIFIED, scriptName, scriptTable);
    return buildMapBackedGsubData(featureListTable, lookupListTable, scriptTableDetails);
}

public org.apache.fontbox.ttf.model.GsubData getGsubData(java.util.Map<java.lang.String, org.apache.fontbox.ttf.table.common.ScriptTable> scriptList, org.apache.fontbox.ttf.table.common.FeatureListTable featureListTable, org.apache.fontbox.ttf.table.common.LookupListTable lookupListTable) {
    org.apache.fontbox.ttf.gsub.GlyphSubstitutionDataExtractor.ScriptTableDetails scriptTableDetails = getSupportedLanguage(scriptList);
    if (scriptTableDetails == null) {
        return org.apache.fontbox.ttf.model.GsubData.NO_DATA_FOUND;
    }
    return buildMapBackedGsubData(featureListTable, lookupListTable, scriptTableDetails);
}

public org.apache.fontbox.ttf.gsub.GsubWorker getGsubWorker(org.apache.fontbox.ttf.CmapLookup cmapLookup, org.apache.fontbox.ttf.model.GsubData gsubData) {
    // TODO this needs to be redesigned / improved because if a font supports several languages,
    // it will choose one of them and maybe not the one expected.
    // See also PDFBOX-5700 and PDFBOX-5729
    // For example, NotoSans-Regular hits Devanagari first
