}

/**
 * Generic method used by Mac and Unix font finders.
 *
 * @return list of natively existing font directories {@inheritDoc }
 */
@java.lang.Override
public java.util.List<java.io.File> find() {
    java.util.List<java.io.File> fontDirList = new java.util.ArrayList<>();
    java.lang.String[] searchableDirectories = getSearchableDirectories();
    if (searchableDirectories != null) {
        for (java.lang.String searchableDirectorie : searchableDirectories) {
            java.io.File fontDir = new java.io.File(searchableDirectorie);
            try {
                if (fontDir.exists() && fontDir.canRead()) {
                    fontDirList.add(fontDir);
                }
            } catch (java.lang.SecurityException e) {
                org.apache.fontbox.util.autodetect.NativeFontDirFinder.LOG.debug("Couldn't get native font directories - ignoring", e);
                // should continue if this fails
            }
        }
    }
    return fontDirList;
}

/**
 * {@inheritDoc }
 *
 * @return a list of detected font files
 */
@java.lang.Override
public java.util.List<java.io.File> find() {
    java.util.List<java.io.File> fontDirList = new java.util.ArrayList<>();
    java.lang.String windir = null;
    try {
        windir = java.lang.System.getProperty("env.windir");
    } catch (java.lang.SecurityException e) {
        org.apache.fontbox.util.autodetect.WindowsFontDirFinder.LOG.debug("Couldn't get Windows font directories - ignoring", e);
        // should continue if this fails
    }
    if (windir == null) {
        try {
            windir = java.lang.System.getenv("windir");
        } catch (java.lang.SecurityException e) {
            org.apache.fontbox.util.autodetect.WindowsFontDirFinder.LOG.debug("Couldn't get Windows font directories - ignoring", e);
            // should continue if this fails
        }
    }
    java.io.File osFontsDir;
    java.io.File psFontsDir;
    if ((windir != null) && (windir.length() > 2)) {
        // remove any trailing '/'
        if (windir.endsWith("/")) {
            windir = windir.substring(0, windir.length() - 1);
        }
        osFontsDir = new java.io.File((windir + java.io.File.separator) + "FONTS");
        if (osFontsDir.exists() && osFontsDir.canRead()) {
            fontDirList.add(osFontsDir);
        }
        psFontsDir = new java.io.File((windir.substring(0, 2) + java.io.File.separator) + "PSFONTS");
        if (psFontsDir.exists() && psFontsDir.canRead()) {
            fontDirList.add(psFontsDir);
        }
    } else {
        java.lang.String osName = java.lang.System.getProperty("os.name");
        java.lang.String windowsDirName = (osName.endsWith("NT")) ? "WINNT" : "WINDOWS";
        // look for true type font folder
        for (char driveLetter = 'C'; driveLetter <= 'E'; driveLetter++) {
            osFontsDir = new java.io.File(((((driveLetter + ":") + java.io.File.separator) + windowsDirName) + java.io.File.separator) + "FONTS");
            try {
                if (osFontsDir.exists() && osFontsDir.canRead()) {
                    fontDirList.add(osFontsDir);
                    break;
                }
            } catch (java.lang.SecurityException e) {
                org.apache.fontbox.util.autodetect.WindowsFontDirFinder.LOG.debug("Couldn't get Windows font directories - ignoring", e);
                // should continue if this fails
            }
        }
        // look for type 1 font folder
        for (char driveLetter = 'C'; driveLetter <= 'E'; driveLetter++) {
            psFontsDir = new java.io.File(((driveLetter + ":") + java.io.File.separator) + "PSFONTS");
            try {
                if (psFontsDir.exists() && psFontsDir.canRead()) {
                    fontDirList.add(psFontsDir);
                    break;
                }
            } catch (java.lang.SecurityException e) {
                org.apache.fontbox.util.autodetect.WindowsFontDirFinder.LOG.debug("Couldn't get Windows font directories - ignoring", e);
                // should continue if this fails
            }
        }
    }
    try {
        java.lang.String localAppData = java.lang.System.getenv("LOCALAPPDATA");
        if ((localAppData != null) && (!localAppData.isEmpty())) {
            java.io.File localFontDir = new java.io.File((((((localAppData + java.io.File.separator) + "Microsoft") + java.io.File.separator) + "Windows") + java.io.File.separator) + "Fonts");
            if (localFontDir.exists() && localFontDir.canRead()) {
                fontDirList.add(localFontDir);
            }
        }
    } catch (java.lang.SecurityException e) {
        org.apache.fontbox.util.autodetect.WindowsFontDirFinder.LOG.debug("Couldn't get LOCALAPPDATA directory - ignoring", e);
        // should continue if this fails
    }
    return fontDirList;
}

