/**
 * Called when a string of text with spacing adjustments is to be shown.
 *
 * @param array
 * 		array of encoded text strings and adjustments
 * @throws IOException
 * 		if there was an error showing the text
 */
public void showTextStrings(org.apache.pdfbox.cos.COSArray array) throws java.io.IOException {
    org.apache.pdfbox.pdmodel.graphics.state.PDTextState textState = getGraphicsState().getTextState();
    float fontSize = textState.getFontSize();
    float horizontalScaling = textState.getHorizontalScaling() / 100.0F;
    org.apache.pdfbox.pdmodel.font.PDFont font = textState.getFont();
    boolean isVertical = false;
    if (font != null) {
        isVertical = font.isVertical();
    }
    for (org.apache.pdfbox.cos.COSBase obj : array) {
        if (obj instanceof org.apache.pdfbox.cos.COSNumber) {
            float tj = ((org.apache.pdfbox.cos.COSNumber) (obj)).floatValue();
            // calculate the combined displacements
            float tx;
            float ty;
            if (isVertical) {
                tx = 0;
                ty = ((-tj) / 1000) * fontSize;
            } else {
                tx = (((-tj) / 1000) * fontSize) * horizontalScaling;
                ty = 0;
            }
            applyTextAdjustment(tx, ty);
        } else if (obj instanceof org.apache.pdfbox.cos.COSString) {
            byte[] string = ((org.apache.pdfbox.cos.COSString) (obj)).getBytes();
            showText(string);
        } else if (obj instanceof org.apache.pdfbox.cos.COSArray) {
            org.apache.pdfbox.contentstream.PDFStreamEngine.LOG.error("Nested arrays are not allowed in an array for TJ operation: {}", obj);
        } else {
            org.apache.pdfbox.contentstream.PDFStreamEngine.LOG.error("Unknown type {} in array for TJ operation: {}", obj.getClass().getSimpleName(), obj);
        }
    }
}

