public java.lang.String getPath() {
    java.lang.StringBuilder sb = new java.lang.StringBuilder();
    sb.append("Root/Pages");
    org.apache.pdfbox.cos.COSDictionary node = dict;
    while (node.containsKey(org.apache.pdfbox.cos.COSName.PARENT)) {
        org.apache.pdfbox.cos.COSDictionary parent = node.getCOSDictionary(org.apache.pdfbox.cos.COSName.PARENT);
        if (parent == null) {
            return "";
        }
        org.apache.pdfbox.cos.COSArray kids = parent.getCOSArray(org.apache.pdfbox.cos.COSName.KIDS);
        if (kids == null) {
            return "";
        }
        int idx = kids.indexOfObject(node);
        if (idx == (-1)) {
            break;
        }
        sb.append("/Kids/[").append(idx).append("]");
        node = parent;
    } 
    return sb.toString();
}

