        org.apache.pdfbox.examples.signature.TSAClient.LOG.error("request: {} ", () -> org.apache.pdfbox.util.Hex.getString(encodedRequest));
        if (response != null) {
            org.apache.pdfbox.examples.signature.TSAClient.LOG.error("response: {}", () -> org.apache.pdfbox.util.Hex.getString(tsaResponse));
            // See https://github.com/bcgit/bc-java/blob/4a10c27a03bddd96cf0a3663564d0851425b27b9/pkix/src/main/java/org/bouncycastle/tsp/TimeStampResponse.java#L159
            if ("response contains wrong nonce value.".equals(e.getMessage())) {
                org.apache.pdfbox.examples.signature.TSAClient.LOG.error("request nonce: {}", () -> request.getNonce().toString(16));
                if (response.getTimeStampToken() != null) {
                    org.bouncycastle.tsp.TimeStampTokenInfo tsi = response.getTimeStampToken().getTimeStampInfo();
                    if ((tsi != null) && (tsi.getNonce() != null)) {
