    result.getParameters().addAll(parameters);
    java.awt.image.BufferedImage image = readJPX(encoded, options, result);
    java.awt.image.Raster raster = image.getRaster();
    switch (raster.getDataBuffer().getDataType()) {
        case java.awt.image.DataBuffer.TYPE_BYTE :
            java.awt.image.DataBufferByte byteBuffer = ((java.awt.image.DataBufferByte) (raster.getDataBuffer()));
            decoded.write(byteBuffer.getData());
            return result;
        case java.awt.image.DataBuffer.TYPE_USHORT :
            java.awt.image.DataBufferUShort wordBuffer = ((java.awt.image.DataBufferUShort) (raster.getDataBuffer()));
            for (short w : wordBuffer.getData()) {
                decoded.write(w >> 8);
                decoded.write(w);
