        case java.awt.image.DataBuffer.TYPE_INT :
            // not yet used (as of October 2018) but works as fallback
            // if we decide to convert to BufferedImage.TYPE_INT_RGB
            int[] ar = new int[raster.getNumBands()];
            for (int y = 0; y < image.getHeight(); ++y) {
                for (int x = 0; x < image.getWidth(); ++x) {
                    raster.getPixel(x, y, ar);
                    for (int i = 0; i < ar.length; ++i) {
                        decoded.write(ar[i]);
                    }
                }
            }
            return result;
        default :
            throw new java.io.IOException(("Data type " + raster.getDataBuffer().getDataType()) + " not implemented");
    }
}

