/**
 * Imports a page from some PDF file as a Form XObject so it can be placed on another page
 * in the target document.
 * <p>
 * You may want to call {@link #wrapInSaveRestore(PDPage) wrapInSaveRestore(PDPage)} before invoking the Form XObject to
 * make sure that the graphics state is reset.
 *
 * @param sourceDoc
 * 		the source PDF document that contains the page to be copied
 * @param page
 * 		the page in the source PDF document to be copied
 * @return a Form XObject containing the original page's content
 * @throws IOException
 * 		if an I/O error occurs
 */
public org.apache.pdfbox.pdmodel.graphics.form.PDFormXObject importPageAsForm(org.apache.pdfbox.pdmodel.PDDocument sourceDoc, org.apache.pdfbox.pdmodel.PDPage page) throws java.io.IOException {
    importOcProperties(sourceDoc);
    org.apache.pdfbox.pdmodel.common.PDStream newStream = new org.apache.pdfbox.pdmodel.common.PDStream(targetDoc, page.getContents(), org.apache.pdfbox.cos.COSName.FLATE_DECODE);
    org.apache.pdfbox.pdmodel.graphics.form.PDFormXObject form = new org.apache.pdfbox.pdmodel.graphics.form.PDFormXObject(newStream);
    // Copy resources
    org.apache.pdfbox.pdmodel.PDResources pageRes = page.getResources();
    org.apache.pdfbox.pdmodel.PDResources formRes = new org.apache.pdfbox.pdmodel.PDResources();
    cloner.cloneMerge(pageRes, formRes);
    form.setResources(formRes);
    // Transfer some values from page to form
    transferDict(page.getCOSObject(), form.getCOSObject(), org.apache.pdfbox.multipdf.LayerUtility.PAGE_TO_FORM_FILTER);
