    java.awt.geom.AffineTransform at = matrix.createAffineTransform();
    org.apache.pdfbox.pdmodel.common.PDRectangle mediaBox = page.getMediaBox();
    org.apache.pdfbox.pdmodel.common.PDRectangle cropBox = page.getCropBox();
    org.apache.pdfbox.pdmodel.common.PDRectangle viewBox = (cropBox != null) ? cropBox : mediaBox;
    // Handle the /Rotation entry on the page dict
    int rotation = page.getRotation();
    // Transform to FOP's user space
    // at.scale(1 / viewBox.getWidth(), 1 / viewBox.getHeight());
    at.translate(mediaBox.getLowerLeftX() - viewBox.getLowerLeftX(), mediaBox.getLowerLeftY() - viewBox.getLowerLeftY());
    switch (rotation) {
        case 90 :
            at.scale(viewBox.getWidth() / viewBox.getHeight(), viewBox.getHeight() / viewBox.getWidth());
            at.translate(0, viewBox.getWidth());
            at.quadrantRotate(3);// 270

            break;
        case 180 :
            at.translate(viewBox.getWidth(), viewBox.getHeight());
            at.quadrantRotate(2);// 180

            break;
        case 270 :
            at.scale(viewBox.getWidth() / viewBox.getHeight(), viewBox.getHeight() / viewBox.getWidth());
            at.translate(viewBox.getHeight(), 0);
            at.quadrantRotate(1);// 90

            break;
        default :
            // no additional transformations necessary
    }
    // Compensate for Crop Boxes not starting at 0,0
    at.translate(-viewBox.getLowerLeftX(), -viewBox.getLowerLeftY());
    if (!at.isIdentity()) {
        form.setMatrix(at);
    }
    org.apache.fontbox.util.BoundingBox bbox = new org.apache.fontbox.util.BoundingBox();
    bbox.setLowerLeftX(viewBox.getLowerLeftX());
    bbox.setLowerLeftY(viewBox.getLowerLeftY());
    bbox.setUpperRightX(viewBox.getUpperRightX());
    bbox.setUpperRightY(viewBox.getUpperRightY());
    form.setBBox(new org.apache.pdfbox.pdmodel.common.PDRectangle(bbox));
    return form;
}

