public org.apache.pdfbox.pdmodel.PDDocument overlay(java.util.Map<java.lang.Integer, java.lang.String> specificPageOverlayMap) throws java.io.IOException {
    java.util.Map<java.lang.String, org.apache.pdfbox.multipdf.Overlay.LayoutPage> layouts = new java.util.HashMap<>();
    java.lang.String path;
    loadPDFs();
    for (java.util.Map.Entry<java.lang.Integer, java.lang.String> e : specificPageOverlayMap.entrySet()) {
        path = e.getValue();
