        if (layoutPage == null) {
            org.apache.pdfbox.pdmodel.PDDocument doc = loadPDF(path);
            layoutPage = createLayoutPageFromDocument(doc);
            layouts.put(path, layoutPage);
            openDocumentsSet.add(doc);
