    splitter.setStartPage(java.lang.Math.max(startPage, 1));
    splitter.setEndPage(java.lang.Math.min(endPage, sourceDocument.getNumberOfPages()));
    splitter.setSplitAtPage((getEndPage() - getStartPage()) + 1);
    java.util.List<org.apache.pdfbox.pdmodel.PDDocument> splitted = splitter.split(sourceDocument);
    return splitted.get(0);
}

/**
