            return beginImageDataOP;
        case ']' :
            // some ']' around without its previous '['
            // this means a PDF is somewhat corrupt but we will continue to parse.
            source.read();
            // must be a better solution than null...
            return org.apache.pdfbox.cos.COSNull.NULL;
        default :
            // we must be an operator
            java.lang.String operator = readOperator().trim();
            if (!operator.isEmpty()) {
                return org.apache.pdfbox.contentstream.operator.Operator.getOperator(operator);
            }
    }
    return null;
}

/**
 * Returns the stream of the XRef.
 *
 * @return the XRef stream
 * @throws IOException
 * 		if something went wrong
 */
public org.apache.pdfbox.cos.COSStream getStream() throws java.io.IOException {
    stream.setItem(org.apache.pdfbox.cos.COSName.TYPE, org.apache.pdfbox.cos.COSName.XREF);
    if (size == (-1)) {
        throw new java.lang.IllegalArgumentException("size is not set in xrefstream");
    }
    stream.setLong(org.apache.pdfbox.cos.COSName.SIZE, size);
    java.util.List<java.lang.Long> indexEntry = getIndexEntry();
    org.apache.pdfbox.cos.COSArray indexAsArray = new org.apache.pdfbox.cos.COSArray();
    for (java.lang.Long i : indexEntry) {
        indexAsArray.add(org.apache.pdfbox.cos.COSInteger.get(i));
    }
    stream.setItem(org.apache.pdfbox.cos.COSName.INDEX, indexAsArray);
    int[] wEntry = getWEntry();
    org.apache.pdfbox.cos.COSArray wAsArray = new org.apache.pdfbox.cos.COSArray();
    for (int j : wEntry) {
        wAsArray.add(org.apache.pdfbox.cos.COSInteger.get(j));
    }
    stream.setItem(org.apache.pdfbox.cos.COSName.W, wAsArray);
    try (java.io.OutputStream outputStream = this.stream.createOutputStream(org.apache.pdfbox.cos.COSName.FLATE_DECODE)) {
        writeStreamData(outputStream, wEntry);
        outputStream.flush();
    }
    java.util.Set<org.apache.pdfbox.cos.COSName> keySet = this.stream.keySet();
    for (org.apache.pdfbox.cos.COSName cosName : keySet) {
        // "Other cross-reference stream entries not listed in Table 17 may be indirect; in fact,
        // some (such as Root in Table 15) shall be indirect."
        if ((org.apache.pdfbox.cos.COSName.ROOT.equals(cosName) || org.apache.pdfbox.cos.COSName.INFO.equals(cosName)) || org.apache.pdfbox.cos.COSName.PREV.equals(cosName)) {
            continue;
        }
        // this one too, because it has already been written in COSWriter.doWriteBody()
        if (org.apache.pdfbox.cos.COSName.ENCRYPT.equals(cosName)) {
            continue;
        }
        org.apache.pdfbox.cos.COSBase dictionaryObject = this.stream.getDictionaryObject(cosName);
        dictionaryObject.setDirect(true);
    }
    return this.stream;
}

/**
 * Parses cross reference tables.
 *
 * @param document
 * 		the corresponding COS document of the pdf.
 * @param startXRefOffset
 * 		start offset of the first table
 * @return the trailer dictionary
 * @throws IOException
 * 		if something went wrong
 */
public org.apache.pdfbox.cos.COSDictionary parseXref(org.apache.pdfbox.cos.COSDocument document, long startXRefOffset) throws java.io.IOException {
    source.seek(startXRefOffset);
    long startXrefOffset = java.lang.Math.max(0, parseStartXref());
    // check the startxref offset
    long fixedOffset = checkXRefOffset(startXrefOffset);
    if (fixedOffset > (-1)) {
        startXrefOffset = fixedOffset;
    }
    document.setStartXref(startXrefOffset);
    long prev = startXrefOffset;
    // ---- parse whole chain of xref tables/object streams using PREV reference
    java.util.Set<java.lang.Long> prevSet = new java.util.HashSet<>();
    org.apache.pdfbox.cos.COSDictionary trailer = null;
    while (prev > 0) {
        // save expected position for loop detection
        prevSet.add(prev);
        // seek to xref table
        source.seek(prev);
        // skip white spaces
        parser.skipSpaces();
        // save current position as well due to skipped spaces
        prevSet.add(source.getPosition());
        // -- parse xref
        if (source.peek() == org.apache.pdfbox.pdfparser.XrefParser.X) {
            // xref table and trailer
            // use existing parser to parse xref table
            if ((!parseXrefTable(prev)) || (!parseTrailer())) {
                throw new java.io.IOException("Expected trailer object at offset " + source.getPosition());
            }
            trailer = xrefTrailerResolver.getCurrentTrailer();
            // check for a XRef stream, it may contain some object ids of compressed objects
            if (trailer.containsKey(org.apache.pdfbox.cos.COSName.XREF_STM)) {
                int streamOffset = trailer.getInt(org.apache.pdfbox.cos.COSName.XREF_STM);
                // check the xref stream reference
                fixedOffset = checkXRefOffset(streamOffset);
                if ((fixedOffset > (-1)) && (fixedOffset != streamOffset)) {
                    org.apache.pdfbox.pdfparser.XrefParser.LOG.warn("/XRefStm offset {} is incorrect, corrected to {}", streamOffset, fixedOffset);
                    streamOffset = ((int) (fixedOffset));
                    trailer.setInt(org.apache.pdfbox.cos.COSName.XREF_STM, streamOffset);
                }
                if (streamOffset > 0) {
                    source.seek(streamOffset);
                    parser.skipSpaces();
                    try {
                        parseXrefObjStream(prev, false);
                        document.setHasHybridXRef();
                    } catch (java.io.IOException ex) {
                        org.apache.pdfbox.pdfparser.XrefParser.LOG.error("Failed to parse /XRefStm at offset {}", streamOffset, ex);
                    }
                } else {
                    org.apache.pdfbox.pdfparser.XrefParser.LOG.error("Skipped XRef stream due to a corrupt offset: {}", streamOffset);
                }
            }
            prev = trailer.getLong(org.apache.pdfbox.cos.COSName.PREV);
        } else {
            // parse xref stream
            prev = parseXrefObjStream(prev, true);
            trailer = xrefTrailerResolver.getCurrentTrailer();
        }
        if (prev > 0) {
            // check the xref table reference
            fixedOffset = checkXRefOffset(prev);
            if ((fixedOffset > (-1)) && (fixedOffset != prev)) {
                prev = fixedOffset;
                trailer.setLong(org.apache.pdfbox.cos.COSName.PREV, prev);
            }
        }
        if (prevSet.contains(prev)) {
            throw new java.io.IOException("/Prev loop at offset " + prev);
        }
    } 
    // ---- build valid xrefs out of the xref chain
    xrefTrailerResolver.setStartxref(startXrefOffset);
    trailer = xrefTrailerResolver.getTrailer();
    document.setTrailer(trailer);
    document.setIsXRefStream(org.apache.pdfbox.pdfparser.XrefTrailerResolver.XRefType.STREAM == xrefTrailerResolver.getXrefType());
    // check the offsets of all referenced objects
    checkXrefOffsets();
    // copy xref table
    document.addXRefTable(xrefTrailerResolver.getXrefTable());
    // remember the highest XRef object number to avoid it being reused in incremental saving
    java.util.Optional<java.lang.Long> maxValue = // 
    // 
    document.getXrefTable().keySet().stream().map(org.apache.pdfbox.cos.COSObjectKey::getNumber).reduce(java.lang.Long::max);
    document.setHighestXRefObjectNumber(maxValue.isPresent() ? maxValue.get() : 0);
    return trailer;
}

/**
 * Returns object numbers which are referenced as contained
 * in object stream with specified object number.
 *
 * This will scan resolved xref table for all entries having negated
 * stream object number as value.
 *
 * @param objstmObjNr
 * 		object number of object stream for which contained object numbers
 * 		should be returned
 * @return set of object numbers referenced for given object stream
or <code>null</code> if {@link #setStartxref(long)} was not
called before so that no resolved xref table exists
 */
public java.util.Set<java.lang.Long> getContainedObjectNumbers(final int objstmObjNr) {
    if (resolvedXrefTrailer == null) {
        return null;
    }
    final java.util.Set<java.lang.Long> refObjNrs = new java.util.HashSet<>();
    final long cmpVal = -objstmObjNr;
    resolvedXrefTrailer.xrefTable.forEach((key, value) -> {
        if (value == cmpVal) {
            refObjNrs.add(key.getNumber());
        }
    });
    return refObjNrs;
}

/**
 * Returns the first trailer if at least one exists.
 *
 * @return the first trailer or null
 */
