/**
 * Compares this object with the specified object for order. Returns a negative integer, zero, or a positive integer
 * as this object is less than, equal to, or greater than the specified object.
 *
 * @param xReferenceEntry
 * 		the object to be compared.
 * @return a negative integer, zero, or a positive integer as this object is less than, equal to, or greater than
the specified object.
 */
@java.lang.Override
public int compareTo(org.apache.pdfbox.pdfparser.xref.XReferenceEntry xReferenceEntry) {
    if (getReferencedKey() == null) {
        return -1;
    } else if ((xReferenceEntry == null) || (xReferenceEntry.getReferencedKey() == null)) {
        return 1;
    }
    return getReferencedKey().compareTo(xReferenceEntry.getReferencedKey());
}

/**
 * Return the stream of PDF data to be signed. Clients should use this method only to create
 * signatures externally. {@link #write(PDDocument)} method should have been called prior. The
 * created signature should be set using {@link #writeExternalSignature(byte[])}.
 * <p>
 * When {@link SignatureInterface} instance is used, COSWriter obtains and writes the signature
 * itself.
 * </p>
 *
 * @return data stream to be signed
 * @throws IllegalStateException
 * 		if PDF is not prepared for external signing
 * @throws IOException
 * 		if input data is closed
 */
public java.io.InputStream getDataToSign() throws java.io.IOException {
    if ((incrementPart == null) || (incrementalInput == null)) {
        throw new java.lang.IllegalStateException("PDF not prepared for signing");
    }
    // range of incremental bytes to be signed (includes /ByteRange but not /Contents)
    int incPartSigOffset = ((int) (signatureOffset - incrementalInput.length()));
    int afterSigOffset = incPartSigOffset + ((int) (signatureLength));
    int[] range = new int[]{ 0, incPartSigOffset, afterSigOffset, incrementPart.length - afterSigOffset };
    return new java.io.SequenceInputStream(new org.apache.pdfbox.io.RandomAccessInputStream(incrementalInput), new org.apache.pdfbox.pdmodel.interactive.digitalsignature.COSFilterInputStream(incrementPart, range));
}

/**
