/**
 * Returns the {@link COSObjectKey} for a given registered {@link COSBase}. Returns null if such an object is not
 * registered.
 *
 * @param object
 * 		The {@link COSBase} a {@link COSObjectKey} shall be determined for.
 * @return key The {@link COSObjectKey}, that matches the registered {@link COSBase}, or null if such an object is
not registered.
 */
public org.apache.pdfbox.cos.COSObjectKey getKey(org.apache.pdfbox.cos.COSBase object) {
    org.apache.pdfbox.cos.COSObjectKey key = null;
    if (object instanceof org.apache.pdfbox.cos.COSObject) {
        key = objectPool.get(((org.apache.pdfbox.cos.COSObject) (object)).getObject());
    }
    if (key == null) {
        return objectPool.get(object);
    }
    return key;
}

/**
 * Update the key and object maps.
 *
 * @param key
 * 		The key, that shall be added.
 * @param object
 * 		The object, that shall be added.
 * @return The actual key, the object has been added for.
 */
public org.apache.pdfbox.cos.COSObjectKey put(org.apache.pdfbox.cos.COSObjectKey key, org.apache.pdfbox.cos.COSBase object) {
    // to avoid to mixup indirect COSInteger objects holding the same value we have to check
    // if the given key is the same than the key which is stored for the "same" base object wihtin the object pool
    // the same is always true for COSFloat, COSBoolean and COSName and under certain circumstances for the remainig
    // types as well
    if ((object == null) || (contains(object) && getKey(object).equals(key))) {
        return null;
    }
    org.apache.pdfbox.cos.COSObjectKey actualKey = key;
    if ((actualKey == null) || contains(actualKey)) {
        highestXRefObjectNumber++;
        actualKey = new org.apache.pdfbox.cos.COSObjectKey(highestXRefObjectNumber, 0);
        object.setKey(actualKey);
    } else {
        highestXRefObjectNumber = java.lang.Math.max(key.getNumber(), highestXRefObjectNumber);
    }
    keyPool.put(actualKey, object);
    objectPool.put(object, actualKey);
    return actualKey;
}

/**
 * Creates {@link COSWriterObjectStream}s for all currently registered objects of this pool, that have been marked
 * as fit for being compressed in this manner. Such object streams may be added to a PDF document and shall be
 * declared in a document's {@link PDFXRefStream} accordingly. The objects contained in such a stream must not be
 * added to the document separately.
 *
 * @return The created {@link COSWriterObjectStream}s for all currently registered compressible objects.
 */
public java.util.List<org.apache.pdfbox.pdfwriter.compress.COSWriterObjectStream> createObjectStreams() {
    java.util.List<org.apache.pdfbox.pdfwriter.compress.COSWriterObjectStream> objectStreams = new java.util.ArrayList<>();
    org.apache.pdfbox.pdfwriter.compress.COSWriterObjectStream objectStream = null;
    for (int i = 0; i < objectStreamObjects.size(); i++) {
        org.apache.pdfbox.cos.COSObjectKey key = objectStreamObjects.get(i);
        if ((objectStream == null) || ((i % parameters.getObjectStreamSize()) == 0)) {
            objectStream = new org.apache.pdfbox.pdfwriter.compress.COSWriterObjectStream(this);
            objectStreams.add(objectStream);
        }
        objectStream.prepareStreamObject(key, objectPool.getObject(key));
    }
    return objectStreams;
}

/**
 * Writes all prepared {@link COSObject}s to the given {@link COSStream}.
 *
 * @param stream
 * 		The stream for the compressed objects.
 * @return The given {@link COSStream} of this object stream.
 * @throws IOException
 * 		Shall be thrown, if writing the object stream failed.
 */
public org.apache.pdfbox.cos.COSStream writeObjectsToStream(org.apache.pdfbox.cos.COSStream stream) throws java.io.IOException {
    int objectCount = preparedKeys.size();
    stream.setItem(org.apache.pdfbox.cos.COSName.TYPE, org.apache.pdfbox.cos.COSName.OBJ_STM);
    stream.setInt(org.apache.pdfbox.cos.COSName.N, objectCount);
    // Prepare the compressible objects for writing.
    java.util.List<java.lang.Long> objectNumbers = new java.util.ArrayList<>(objectCount);
    java.util.List<org.apache.pdfbox.pdfwriter.compress.COSWriterObjectStream.DirectAccessByteArrayOutputStream> objectsBuffer = new java.util.ArrayList<>(objectCount);
    for (int i = 0; i < objectCount; i++) {
        try (org.apache.pdfbox.pdfwriter.compress.COSWriterObjectStream.DirectAccessByteArrayOutputStream partialOutput = new org.apache.pdfbox.pdfwriter.compress.COSWriterObjectStream.DirectAccessByteArrayOutputStream()) {
            objectNumbers.add(preparedKeys.get(i).getNumber());
            org.apache.pdfbox.cos.COSBase base = preparedObjects.get(i);
            writeObject(partialOutput, base, true);
            objectsBuffer.add(partialOutput);
        }
    }
    // Deduce the object stream byte offset map.
    byte[] offsetsMapBuffer;
    long nextObjectOffset = 0;
    try (java.io.ByteArrayOutputStream partialOutput = new java.io.ByteArrayOutputStream()) {
        for (int i = 0; i < objectNumbers.size(); i++) {
            partialOutput.write(java.lang.String.valueOf(objectNumbers.get(i)).getBytes(java.nio.charset.StandardCharsets.ISO_8859_1));
            partialOutput.write(org.apache.pdfbox.pdfwriter.COSWriter.SPACE);
            partialOutput.write(java.lang.String.valueOf(nextObjectOffset).getBytes(java.nio.charset.StandardCharsets.ISO_8859_1));
            partialOutput.write(org.apache.pdfbox.pdfwriter.COSWriter.SPACE);
            nextObjectOffset += objectsBuffer.get(i).size();
        }
        offsetsMapBuffer = partialOutput.toByteArray();
    }
    // Write Flate compressed object stream data.
    try (java.io.OutputStream output = stream.createOutputStream(org.apache.pdfbox.cos.COSName.FLATE_DECODE)) {
        output.write(offsetsMapBuffer);
        stream.setInt(org.apache.pdfbox.cos.COSName.FIRST, offsetsMapBuffer.length);
        for (org.apache.pdfbox.pdfwriter.compress.COSWriterObjectStream.DirectAccessByteArrayOutputStream rawObject : objectsBuffer) {
            output.write(rawObject.getRawData(), 0, rawObject.size());
        }
    }
    return stream;
}

