/**
 * Performs exponential interpolation
 *
 * {@inheritDoc }
 */
@java.lang.Override
public float[] eval(float[] input) throws java.io.IOException {
    // exponential interpolation
    float xToN = ((float) (java.lang.Math.pow(input[0], exponent)));// x^exponent

    float[] result = new float[java.lang.Math.min(c0.size(), c1.size())];
    for (int j = 0; j < result.length; j++) {
        float c0j = ((org.apache.pdfbox.cos.COSNumber) (c0.get(j))).floatValue();
        float c1j = ((org.apache.pdfbox.cos.COSNumber) (c1.get(j))).floatValue();
        result[j] = c0j + (xToN * (c1j - c0j));
    }
    return clipToRange(result);
}

/**
 * {@inheritDoc }
 */
@java.lang.Override
public float[] eval(float[] input) throws java.io.IOException {
    // This function is known as a "stitching" function. Based on the input, it decides which child function to call.
    // All functions in the array are 1-value-input functions
    // See PDF Reference section 3.9.3.
    org.apache.pdfbox.pdmodel.common.function.PDFunction function = null;
    float x = input[0];
    org.apache.pdfbox.pdmodel.common.PDRange domain = getDomainForInput(0);
    // clip input value to domain
    x = clipToRange(x, domain.getMin(), domain.getMax());
    if (functionsArray == null) {
        org.apache.pdfbox.cos.COSArray ar = getFunctions();
        functionsArray = new org.apache.pdfbox.pdmodel.common.function.PDFunction[ar.size()];
        for (int i = 0; i < ar.size(); ++i) {
            functionsArray[i] = org.apache.pdfbox.pdmodel.common.function.PDFunction.create(ar.getObject(i));
        }
    }
    if (functionsArray.length == 1) {
        // This doesn't make sense but it may happen ...
        function = functionsArray[0];
        org.apache.pdfbox.pdmodel.common.PDRange encRange = getEncodeForParameter(0);
        x = interpolate(x, domain.getMin(), domain.getMax(), encRange.getMin(), encRange.getMax());
    } else {
        if (boundsValues == null) {
            boundsValues = getBounds().toFloatArray();
        }
        int boundsSize = boundsValues.length;
        // create a combined array containing the domain and the bounds values
        // domain.min, bounds[0], bounds[1], ...., bounds[boundsSize-1], domain.max
        float[] partitionValues = new float[boundsSize + 2];
        int partitionValuesSize = partitionValues.length;
        partitionValues[0] = domain.getMin();
        partitionValues[partitionValuesSize - 1] = domain.getMax();
        java.lang.System.arraycopy(boundsValues, 0, partitionValues, 1, boundsSize);
        // find the partition
        for (int i = 0; i < (partitionValuesSize - 1); i++) {
            if ((x >= partitionValues[i]) && ((x < partitionValues[i + 1]) || ((i == (partitionValuesSize - 2)) && (java.lang.Float.compare(x, partitionValues[i + 1]) == 0)))) {
                function = functionsArray[i];
                org.apache.pdfbox.pdmodel.common.PDRange encRange = getEncodeForParameter(i);
                x = interpolate(x, partitionValues[i], partitionValues[i + 1], encRange.getMin(), encRange.getMax());
                break;
            }
        }
    }
    if (function == null) {
        throw new java.io.IOException("partition not found in type 3 function");
    }
    float[] functionValues = new float[]{ x };
    // calculate the output values using the chosen function
    float[] functionResult = function.eval(functionValues);
    // clip to range if available
    return clipToRange(functionResult);
}

