/**
 * {@inheritDoc }
 */
@java.lang.Override
public float[] eval(float[] input) throws java.io.IOException {
    // Setup the input values
    org.apache.pdfbox.pdmodel.common.function.type4.ExecutionContext context = new org.apache.pdfbox.pdmodel.common.function.type4.ExecutionContext(org.apache.pdfbox.pdmodel.common.function.PDFunctionType4.OPERATORS);
    for (int i = 0; i < input.length; i++) {
        org.apache.pdfbox.pdmodel.common.PDRange domain = getDomainForInput(i);
        float value = clipToRange(input[i], domain.getMin(), domain.getMax());
        context.getStack().push(value);
    }
    // Execute the type 4 function.
    instructions.execute(context);
    // Extract the output values
    int numberOfOutputValues = getNumberOfOutputParameters();
    int numberOfActualOutputValues = context.getStack().size();
    if (numberOfActualOutputValues < numberOfOutputValues) {
        throw new java.lang.IllegalStateException(((("The type 4 function returned " + numberOfActualOutputValues) + " values but the Range entry indicates that ") + numberOfOutputValues) + " values be returned.");
    }
    float[] outputValues = new float[numberOfOutputValues];
    for (int i = numberOfOutputValues - 1; i >= 0; i--) {
        org.apache.pdfbox.pdmodel.common.PDRange range = getRangeForOutput(i);
        outputValues[i] = context.popReal();
        outputValues[i] = clipToRange(outputValues[i], range.getMin(), range.getMax());
    }
    // Return the resulting array
    return outputValues;
}

