 * 		The stream to decrypt.
 * @param objNum
 * 		The object number.
 * @param genNum
 * 		The object generation number.
 * @throws IOException
 * 		If there is an error getting the stream data.
 */
public void decryptStream(org.apache.pdfbox.cos.COSStream stream, long objNum, long genNum) throws java.io.IOException {
    // Stream encrypted with identity filter
