        return;
    }
    org.apache.pdfbox.cos.COSBase type = stream.getCOSName(org.apache.pdfbox.cos.COSName.TYPE);
    if ((!decryptMetadata) && org.apache.pdfbox.cos.COSName.METADATA.equals(type)) {
        return;
    }
    // "The cross-reference stream shall not be encrypted"
    if (org.apache.pdfbox.cos.COSName.XREF.equals(type)) {
        return;
    }
    if (org.apache.pdfbox.cos.COSName.METADATA.equals(type)) {
        byte[] buf;
        // PDFBOX-3229 check case where metadata is not encrypted despite /EncryptMetadata missing
        try (java.io.InputStream is = stream.createRawInputStream()) {
            int nBytes = 10;
            buf = is.readNBytes(nBytes);
            int isResult = buf.length;
            if (buf.length != nBytes) {
                org.apache.pdfbox.pdmodel.encryption.SecurityHandler.LOG.debug("Tried reading {} bytes but only {} bytes read", buf.length, isResult);
            }
        }
        if (java.util.Arrays.equals(buf, "<?xpacket ".getBytes(java.nio.charset.StandardCharsets.ISO_8859_1))) {
            org.apache.pdfbox.pdmodel.encryption.SecurityHandler.LOG.warn("Metadata is not encrypted, but was expected to be");
            org.apache.pdfbox.pdmodel.encryption.SecurityHandler.LOG.warn("Read PDF specification about EncryptMetadata (default value: true)");
            return;
        }
    }
    decryptDictionary(stream, objNum, genNum);
    // the input and the output stream of a still encrypted COSStream aren't no longer based
    // on the same object so that it is safe to omit the intermediate ByteArrayStream
    // 
    try (java.io.InputStream encryptedStream = stream.createRawInputStream();java.io.OutputStream output = stream.createRawOutputStream()) {
        /* decrypt */
        encryptData(objNum, genNum, encryptedStream, output, true);
    } catch (java.io.IOException ex) {
        org.apache.pdfbox.pdmodel.encryption.SecurityHandler.LOG.error("{} thrown when decrypting object {} {} obj", ex.getClass().getSimpleName(), objNum, genNum);
        throw ex;
    }
}

/**
