@java.lang.Override
public java.awt.geom.GeneralPath getNormalizedPath(int code) throws java.io.IOException {
    java.awt.geom.GeneralPath path = null;
    if ((otf != null) && otf.isPostScript()) {
        path = getPathFromOutlines(code);
    } else {
        int gid = codeToGID(code);
        path = getPath(code);
        // Acrobat only draws GID 0 for embedded CIDFonts, see PDFBOX-2372
        if ((gid == 0) && (!isEmbedded())) {
            path = null;
        }
    }
    if (path == null) {
        // empty glyph (e.g. space, newline)
        return new java.awt.geom.GeneralPath();
    }
    if (ttf.getUnitsPerEm() != 1000) {
        float scale = 1000.0F / ttf.getUnitsPerEm();
        // PDFBOX-5567: clone() to avoid repeated modification on cached path
        path = ((java.awt.geom.GeneralPath) (path.clone()));
        path.transform(java.awt.geom.AffineTransform.getScaleInstance(scale, scale));
    }
    return path;
}

@java.lang.Override
public java.awt.geom.GeneralPath getPath(int code) throws java.io.IOException {
    if ((otf != null) && otf.isPostScript()) {
        java.awt.geom.GeneralPath path = getPathFromOutlines(code);
        return path == null ? new java.awt.geom.GeneralPath() : path;
    }
    int gid = codeToGID(code);
    org.apache.fontbox.ttf.GlyphData glyph = ttf.getGlyph().getGlyph(gid);
    if (glyph != null) {
        return glyph.getPath();
    }
    return new java.awt.geom.GeneralPath();
}

@java.lang.Override
public float getWidthFromFont(int code) throws java.io.IOException {
    int gid = codeToGID(code);
    float width = ttf.getAdvanceWidth(gid);
    int unitsPerEM = ttf.getUnitsPerEm();
    if (unitsPerEM != 1000) {
        width *= 1000.0F / unitsPerEM;
    }
    return width;
}

/**
 * Encodes the given string for use in a PDF content stream.
 *
 * @param text
 * 		Any Unicode text.
 * @return Array of PDF content stream bytes.
 * @throws IOException
 * 		If the text could not be encoded.
 * @throws IllegalArgumentException
 * 		if a character isn't supported by the font.
 */
public final byte[] encode(java.lang.String text) throws java.io.IOException {
    java.io.ByteArrayOutputStream out = new java.io.ByteArrayOutputStream(java.lang.Math.max(32, text.length()));
    int offset = 0;
    while (offset < text.length()) {
        int codePoint = text.codePointAt(offset);
        // multi-byte encoding with 1 to 4 bytes
        byte[] bytes = encode(codePoint);
        out.writeBytes(bytes);
        offset += java.lang.Character.charCount(codePoint);
    } 
    return out.toByteArray();
}

/**
 * This will get the average font width for all characters.
 *
 * @return The width is in 1000 unit of text space, ie 333 or 777
 */
// todo: this method is highly suspicious, the average glyph width is not usually a good metric
@java.lang.Override
public float getAverageFontWidth() {
    float average;
    if (java.lang.Float.compare(avgFontWidth, 0.0F) != 0) {
        average = avgFontWidth;
    } else {
        float totalWidth = 0.0F;
        float characterCount = 0.0F;
        org.apache.pdfbox.cos.COSArray widths = dict.getCOSArray(org.apache.pdfbox.cos.COSName.WIDTHS);
        if (widths != null) {
            for (int i = 0; i < widths.size(); i++) {
                org.apache.pdfbox.cos.COSBase base = widths.getObject(i);
                if (base instanceof org.apache.pdfbox.cos.COSNumber) {
                    org.apache.pdfbox.cos.COSNumber fontWidth = ((org.apache.pdfbox.cos.COSNumber) (base));
                    float floatValue = fontWidth.floatValue();
                    if (floatValue > 0) {
                        totalWidth += floatValue;
                        characterCount += 1;
                    }
                }
            }
        }
        if (totalWidth > 0) {
            average = totalWidth / characterCount;
        } else {
            average = 0;
        }
        avgFontWidth = average;
    }
    return average;
}

/**
 * Determines the width of the space character. This is very important for text extraction.
 *
 * @return the width of the space character
 */
public float getSpaceWidth() {
    if (java.lang.Float.compare(fontWidthOfSpace, -1.0F) == 0) {
        try {
            if ((toUnicodeCMap != null) && dict.containsKey(org.apache.pdfbox.cos.COSName.TO_UNICODE)) {
                int spaceMapping = toUnicodeCMap.getSpaceMapping();
                if (spaceMapping > (-1)) {
                    fontWidthOfSpace = getWidth(spaceMapping);
                }
            } else {
                try {
                    // PDFBOX-5920: try with encoding, which gets the correct code
                    fontWidthOfSpace = getStringWidth(" ");
                } catch (java.lang.IllegalArgumentException | java.lang.UnsupportedOperationException ex) {
                    // Happens if space is not available in the font
                    // or if encoding isn't implemented
                    org.apache.pdfbox.pdmodel.font.PDFont.LOG.debug(ex.getMessage(), ex);
                }
                if (fontWidthOfSpace <= 0) {
                    fontWidthOfSpace = getWidth(32);
                }
            }
            // try to get it from the font itself
            if (fontWidthOfSpace <= 0) {
                fontWidthOfSpace = getWidthFromFont(32);
                // use the average font width as fall back
                if (fontWidthOfSpace <= 0) {
                    fontWidthOfSpace = getAverageFontWidth();
                }
            }
        } catch (java.lang.Exception e) {
            org.apache.pdfbox.pdmodel.font.PDFont.LOG.error("Can't determine the width of the space character for font {}, assuming 250", getName(), e);
            fontWidthOfSpace = 250.0F;
        }
        org.apache.pdfbox.pdmodel.font.PDFont.LOG.debug("Space width for font {} is {}", getName(), fontWidthOfSpace);
    }
    return fontWidthOfSpace;
}

/**
 * Returns the width of the given Unicode string.
 *
 * @param text
 * 		The text to get the width of.
 * @return The width of the string in 1/1000 units of text space.
 * @throws IOException
 * 		If there is an error getting the width information.
 * @throws IllegalArgumentException
 * 		if a character isn't supported by the font.
 */
public float getStringWidth(java.lang.String text) throws java.io.IOException {
    byte[] bytes = encode(text);
    java.io.ByteArrayInputStream in = new java.io.ByteArrayInputStream(bytes);
    float width = 0;
    while (in.available() > 0) {
        int code = readCode(in);
        width += getWidth(code);
    } 
    return width;
}

@java.lang.Override
public float getWidth(int code) throws java.io.IOException {
    java.lang.Float width = codeToWidthMap.get(code);
    if (width != null) {
        return width;
    }
    // Acrobat overrides the widths in the font program on the conforming reader's system with
    // the widths specified in the font dictionary." (Adobe Supplement to the ISO 32000)
    // 
    // Note: The Adobe Supplement says that the override happens "If the font program is not
    // embedded", however PDFBOX-427 shows that it also applies to embedded fonts.
    // Type1, Type1C, Type3
    if ((dict.getDictionaryObject(org.apache.pdfbox.cos.COSName.WIDTHS) != null) || dict.containsKey(org.apache.pdfbox.cos.COSName.MISSING_WIDTH)) {
        int firstChar = dict.getInt(org.apache.pdfbox.cos.COSName.FIRST_CHAR, -1);
        int lastChar = dict.getInt(org.apache.pdfbox.cos.COSName.LAST_CHAR, -1);
        int siz = getWidths().size();
        int idx = code - firstChar;
        if ((((siz > 0) && (code >= firstChar)) && (code <= lastChar)) && (idx < siz)) {
            width = getWidths().get(idx);
            if (width == null) {
                width = 0.0F;
            }
            codeToWidthMap.put(code, width);
            return width;
        }
        org.apache.pdfbox.pdmodel.font.PDFontDescriptor fd = getFontDescriptor();
        if (fd != null) {
            // get entry from /MissingWidth entry
            width = fd.getMissingWidth();
            codeToWidthMap.put(code, width);
            return width;
        }
    }
    // standard 14 font widths are specified by an AFM
    if (isStandard14()) {
        width = getStandard14Width(code);
        codeToWidthMap.put(code, width);
        return width;
    }
    // if there's nothing to override with, then obviously we fall back to the font
    width = getWidthFromFont(code);
    codeToWidthMap.put(code, width);
    return width;
}

/**
 * Returns true if this font is one of the "Standard 14" fonts and receives special handling.
 *
 * @return true if this font is one of the "Standard 14" fonts
 */
public boolean isStandard14() {
    // this logic is based on Acrobat's behaviour, see PDFBOX-2372
    // embedded fonts never get special treatment
    if (isEmbedded()) {
        return false;
    }
    // if the name matches, this is a Standard 14 font
    return org.apache.pdfbox.pdmodel.font.Standard14Fonts.containsName(getName());
}

/**
 * Returns the Unicode character sequence which corresponds to the given character code.
 *
 * @param code
 * 		character code
 * @return Unicode character(s)
 */
public java.lang.String toUnicode(int code) {
    // if the font dictionary containsName a ToUnicode CMap, use that CMap
    if (toUnicodeCMap != null) {
        if (((toUnicodeCMap.getName() != null) && toUnicodeCMap.getName().startsWith("Identity-")) && ((dict.getCOSName(org.apache.pdfbox.cos.COSName.TO_UNICODE) != null) || (!toUnicodeCMap.hasUnicodeMappings()))) {
            // handle the undocumented case of using Identity-H/V as a ToUnicode CMap, this
            // isn't actually valid as the Identity-x CMaps are code->CID maps, not
            // code->Unicode maps. See sample_fonts_solidconvertor.pdf for an example.
            // PDFBOX-3123: do this only if the /ToUnicode entry is a name
            // PDFBOX-4322: identity streams are OK too
            return java.lang.String.valueOf(((char) (code)));
        } else {
            if ((code < 256) && (!(this instanceof org.apache.pdfbox.pdmodel.font.PDType0Font))) {
                org.apache.pdfbox.cos.COSName encoding = dict.getCOSName(org.apache.pdfbox.cos.COSName.ENCODING);
                if ((encoding != null) && (!encoding.getName().startsWith("Identity"))) {
                    // due to the conversion to an int it is no longer possible to determine
                    // if the code is based on a one or two byte value. We should consider to
                    // refactor that part of the code.
                    // However, simple fonts with a predefined encoding are using one byte codes so that
                    // we can limit the CMap mappings to one byte codes by passing the origin length
                    return toUnicodeCMap.toUnicode(code, 1);
                }
            }
            return toUnicodeCMap.toUnicode(code);
        }
    }
    // if no value has been produced, there is no way to obtain Unicode for the character.
    // this behaviour can be overridden is subclasses, but this method *must* return null here
    return null;
}

