@java.lang.Override
public boolean isStandard14() {
    // this logic is based on Acrobat's behaviour, see PDFBOX-2372
    // the Encoding entry cannot have Differences if we want "standard 14" font handling
    if (getEncoding() instanceof org.apache.pdfbox.pdmodel.font.encoding.DictionaryEncoding) {
        org.apache.pdfbox.pdmodel.font.encoding.DictionaryEncoding dictionary = ((org.apache.pdfbox.pdmodel.font.encoding.DictionaryEncoding) (getEncoding()));
        if (!dictionary.getDifferences().isEmpty()) {
            // we also require that the differences are actually different, see PDFBOX-1900 with
            // the file from PDFBOX-2192 on Windows
            org.apache.pdfbox.pdmodel.font.encoding.Encoding baseEncoding = dictionary.getBaseEncoding();
            for (java.util.Map.Entry<java.lang.Integer, java.lang.String> entry : dictionary.getDifferences().entrySet()) {
                if (!entry.getValue().equals(baseEncoding.getName(entry.getKey()))) {
                    return false;
                }
            }
        }
    }
    return super.isStandard14();
}

