        java.lang.Boolean result = isFontSymbolic();
        if (result != null) {
            isSymbolic = result;
        } else {
            // unless we can prove that the font is non-symbolic, we assume that it is not
            isSymbolic = true;
        }
    }
    return isSymbolic;
}

@java.lang.Override
public java.lang.String toUnicode(int code, org.apache.pdfbox.pdmodel.font.encoding.GlyphList customGlyphList) {
    // allow the glyph list to be overridden for the purpose of extracting Unicode
    // we only do this when the font's glyph list is the AGL, to avoid breaking Zapf Dingbats
    org.apache.pdfbox.pdmodel.font.encoding.GlyphList unicodeGlyphList;
    if (this.glyphList == org.apache.pdfbox.pdmodel.font.encoding.GlyphList.getAdobeGlyphList()) {
        unicodeGlyphList = customGlyphList;
    } else {
        unicodeGlyphList = this.glyphList;
    }
    // first try to use a ToUnicode CMap
    java.lang.String unicode = super.toUnicode(code);
    if (unicode != null) {
        return unicode;
    }
    // if the font is a "simple font" and uses MacRoman/MacExpert/WinAnsi[Encoding]
    // or has Differences with names from only Adobe Standard and/or Symbol, then:
    // 
    // a) Map the character codes to names
    // b) Look up the name in the Adobe Glyph List to obtain the Unicode value
    java.lang.String name = null;
    if (encoding != null) {
        name = encoding.getName(code);
        unicode = unicodeGlyphList.toUnicode(name);
        if (unicode != null) {
            return unicode;
        }
    }
    // if no value has been produced, there is no way to obtain Unicode for the character.
    if (org.apache.pdfbox.pdmodel.font.PDSimpleFont.LOG.isWarnEnabled() && (!noUnicode.contains(code))) {
        // we keep track of which warnings have been issued, so we don't log multiple times
        noUnicode.add(code);
        if (name != null) {
            org.apache.pdfbox.pdmodel.font.PDSimpleFont.LOG.warn("No Unicode mapping for {} ({}) in font {}", name, code, getName());
        } else {
            org.apache.pdfbox.pdmodel.font.PDSimpleFont.LOG.warn("No Unicode mapping for character code {} in font {}", code, getName());
        }
    }
    return null;
}

/**
 * Returns the GID for the given character code.
 *
 * @param code
 * 		character code
 * @return GID (glyph index)
 * @throws IOException
 * 		if the data could not be read
 */
public int codeToGID(int code) throws java.io.IOException {
    extractCmapTable();
    int gid = 0;
    // non-symbolic
    if (!isSymbolic()) {
        java.lang.String name = encoding.getName(code);
        if (".notdef".equals(name)) {
            return 0;
        } else {
            // (3, 1) - (Windows, Unicode)
            if (cmapWinUnicode != null) {
                java.lang.String unicode = org.apache.pdfbox.pdmodel.font.encoding.GlyphList.getAdobeGlyphList().toUnicode(name);
                if (unicode != null) {
                    int uni = unicode.codePointAt(0);
                    gid = cmapWinUnicode.getGlyphId(uni);
                }
            }
            // (1, 0) - (Macintosh, Roman)
            if ((gid == 0) && (cmapMacRoman != null)) {
                java.lang.Integer macCode = org.apache.pdfbox.pdmodel.font.PDTrueTypeFont.INVERTED_MACOS_ROMAN.get(name);
                if (macCode != null) {
                    gid = cmapMacRoman.getGlyphId(macCode);
                }
            }
            // 'post' table
            if (gid == 0) {
                gid = ttf.nameToGID(name);
            }
        }
    } else // symbolic
    {
        // PDFBOX-4755 / PDF.js #5501
        // PDFBOX-3965: fallback for font has that the symbol flag but isn't
        if (cmapWinUnicode != null) {
            if ((encoding instanceof org.apache.pdfbox.pdmodel.font.encoding.WinAnsiEncoding) || (encoding instanceof org.apache.pdfbox.pdmodel.font.encoding.MacRomanEncoding)) {
                java.lang.String name = encoding.getName(code);
                if (".notdef".equals(name)) {
                    return 0;
                }
                java.lang.String unicode = org.apache.pdfbox.pdmodel.font.encoding.GlyphList.getAdobeGlyphList().toUnicode(name);
                if (unicode != null) {
                    int uni = unicode.codePointAt(0);
                    gid = cmapWinUnicode.getGlyphId(uni);
                }
            } else {
                gid = cmapWinUnicode.getGlyphId(code);
            }
        }
        // (3, 0) - (Windows, Symbol)
        if ((gid == 0) && (cmapWinSymbol != null)) {
            gid = cmapWinSymbol.getGlyphId(code);
            if ((code >= 0) && (code <= 0xff)) {
                // the CMap may use one of the following code ranges,
                // so that we have to add the high byte to get the
                // mapped value
                if (gid == 0) {
                    // F000 - F0FF
                    gid = cmapWinSymbol.getGlyphId(code + org.apache.pdfbox.pdmodel.font.PDTrueTypeFont.START_RANGE_F000);
                }
                if (gid == 0) {
                    // F100 - F1FF
                    gid = cmapWinSymbol.getGlyphId(code + org.apache.pdfbox.pdmodel.font.PDTrueTypeFont.START_RANGE_F100);
                }
                if (gid == 0) {
                    // F200 - F2FF
                    gid = cmapWinSymbol.getGlyphId(code + org.apache.pdfbox.pdmodel.font.PDTrueTypeFont.START_RANGE_F200);
                }
            }
        }
        // (1, 0) - (Mac, Roman)
        if ((gid == 0) && (cmapMacRoman != null)) {
            gid = cmapMacRoman.getGlyphId(code);
        }
    }
    return gid;
}

