@java.lang.Override
public java.awt.geom.GeneralPath getNormalizedPath(int code) throws java.io.IOException {
    java.awt.geom.GeneralPath path = null;
    if ((otf != null) && otf.isPostScript()) {
        path = getPathFromOutlines(code);
    } else {
        int gid = codeToGID(code);
        path = getPath(code);
        // Acrobat only draws GID 0 for embedded or "Standard 14" fonts, see PDFBOX-2372
        if (((gid == 0) && (!isEmbedded())) && (!isStandard14())) {
            path = null;
        }
    }
    if (path == null) {
        return new java.awt.geom.GeneralPath();
    }
    if (ttf.getUnitsPerEm() != 1000) {
        float scale = 1000.0F / ttf.getUnitsPerEm();
        // path will have to be cloned if it is cached in the future, see PDFBOX-5567
        path.transform(java.awt.geom.AffineTransform.getScaleInstance(scale, scale));
    }
    return path;
}

@java.lang.Override
public java.awt.geom.GeneralPath getPath(int code) throws java.io.IOException {
    if ((otf != null) && otf.isPostScript()) {
        java.awt.geom.GeneralPath path = getPathFromOutlines(code);
        return path == null ? new java.awt.geom.GeneralPath() : path;
    }
    int gid = codeToGID(code);
    org.apache.fontbox.ttf.GlyphTable glyphTable = ttf.getGlyph();
    if (glyphTable == null) {
        // needs to be caught earlier, see PDFBOX-5587 and PDFBOX-3488
        throw new java.io.IOException(("glyf table is missing in font " + getName()) + ", please report this file");
    }
    org.apache.fontbox.ttf.GlyphData glyph = glyphTable.getGlyph(gid);
    // some glyphs have no outlines (e.g. space, table, newline)
    if (glyph == null) {
        return new java.awt.geom.GeneralPath();
    } else {
        return glyph.getPath();
    }
}

@java.lang.Override
public java.awt.geom.GeneralPath getPath(java.lang.String name) throws java.io.IOException {
    // handle glyph names and uniXXXX names
    int gid = ttf.nameToGID(name);
    if (gid == 0) {
        try {
            // handle GID pseudo-names
            gid = java.lang.Integer.parseInt(name);
            if (gid > ttf.getNumberOfGlyphs()) {
                gid = 0;
            }
        } catch (java.lang.NumberFormatException e) {
            gid = 0;
        }
    }
    // I'm assuming .notdef paths are not drawn, as it PDFBOX-2421
    if (gid == 0) {
        return new java.awt.geom.GeneralPath();
    }
    org.apache.fontbox.ttf.GlyphData glyph = ttf.getGlyph().getGlyph(gid);
    if (glyph != null) {
        return glyph.getPath();
    } else {
        return new java.awt.geom.GeneralPath();
    }
}

@java.lang.Override
public float getWidthFromFont(int code) throws java.io.IOException {
    int gid = codeToGID(code);
    float width = ttf.getAdvanceWidth(gid);
    float unitsPerEM = ttf.getUnitsPerEm();
    if (java.lang.Float.compare(unitsPerEM, 1000) != 0) {
        width *= 1000.0F / unitsPerEM;
    }
    return width;
}

