@java.lang.Override
public java.lang.String toUnicode(int code) {
    // try to use a ToUnicode CMap
    java.lang.String unicode = super.toUnicode(code);
    if (unicode != null) {
        return unicode;
    }
    // Use identity mapping if the given ToUnicode CMap doesn't provide any valid mapping
    // a predefined map shall only be used if there isn't any ToUnicode CMap
    // PDFBOX-6022: not when there's a predefined cmap
    if ((getToUnicodeCMap() != null) && (!isCMapPredefined)) {
        return java.lang.Character.toString(((char) (code)));
    }
    if ((isCMapPredefined || isDescendantCJK) && (cMapUCS2 != null)) {
        // if the font is composite and uses a predefined cmap (excluding Identity-H/V) then
        // or if its descendant font uses Adobe-GB1/CNS1/Japan1/Korea1
        // a) Map the character code to a character identifier (CID) according to the font?s CMap
        int cid = codeToCID(code);
        // e) Map the CID according to the CMap from step d), producing a Unicode value
        return cMapUCS2.toUnicode(cid);
    }
    // PDFBOX-5324: try to get unicode from font cmap
    if (descendantFont instanceof org.apache.pdfbox.pdmodel.font.PDCIDFontType2) {
        org.apache.fontbox.ttf.TrueTypeFont font = ((org.apache.pdfbox.pdmodel.font.PDCIDFontType2) (descendantFont)).getTrueTypeFont();
        if (font != null) {
            try {
                org.apache.fontbox.ttf.CmapLookup cmap = font.getUnicodeCmapLookup(false);
                if (cmap != null) {
                    int gid;
                    if (descendantFont.isEmbedded()) {
                        // original PDFBOX-5324 supported only embedded fonts
                        gid = descendantFont.codeToGID(code);
                    } else {
                        // PDFBOX-5331: this bypasses the fallback attempt in
                        // PDCIDFontType2.codeToGID() which would bring a stackoverflow
                        gid = descendantFont.codeToCID(code);
                    }
                    java.util.List<java.lang.Integer> codes = cmap.getCharCodes(gid);
                    if ((codes != null) && (!codes.isEmpty())) {
                        return java.lang.Character.toString(((char) (int) (codes.get(0))));
                    }
                }
            } catch (java.io.IOException e) {
                org.apache.pdfbox.pdmodel.font.PDType0Font.LOG.warn("get unicode from font cmap fail", e);
            }
        }
    }
    if (org.apache.pdfbox.pdmodel.font.PDType0Font.LOG.isWarnEnabled() && (!noUnicode.contains(code))) {
        // if no value has been produced, there is no way to obtain Unicode for the character.
        java.lang.String cid = "CID+" + codeToCID(code);
        org.apache.pdfbox.pdmodel.font.PDType0Font.LOG.warn("No Unicode mapping for {} ({}) in font {}", cid, code, getName());
        // we keep track of which warnings have been issued, so we don't log multiple times
        noUnicode.add(code);
    }
    return null;
}

