@java.lang.Override
public java.awt.geom.GeneralPath getNormalizedPath(int code) throws java.io.IOException {
    java.lang.String name = getEncoding().getName(code);
    name = getNameInFont(name);
    if ("nbspace".equals(name)) {
        if (!hasGlyph("space")) {
            return new java.awt.geom.GeneralPath();
        }
        name = "space";
    } else if ("sfthyphen".equals(name)) {
        name = "hyphen";
    }
    java.awt.geom.GeneralPath path = getPath(name);
    if (path == null) {
        return getPath(".notdef");
    }
    return path;
}

