                float y = ((org.apache.pdfbox.cos.COSNumber) (arguments.get(3))).floatValue();
                return new org.apache.pdfbox.pdmodel.common.PDRectangle(x, y, ((org.apache.pdfbox.cos.COSNumber) (arguments.get(4))).floatValue() - x, ((org.apache.pdfbox.cos.COSNumber) (arguments.get(5))).floatValue() - y);
