@java.lang.Override
public float getHeight(int code) throws java.io.IOException {
    org.apache.pdfbox.pdmodel.font.PDFontDescriptor desc = getFontDescriptor();
    if (desc != null) {
        // the following values are all more or less accurate at least all are average
        // values. Maybe we'll find another way to get those value for every single glyph
        // in the future if needed
        org.apache.pdfbox.pdmodel.common.PDRectangle bbox = desc.getFontBoundingBox();
        float retval = 0;
        if (bbox != null) {
            retval = bbox.getHeight() / 2;
        }
        if (java.lang.Float.compare(retval, 0) == 0) {
            retval = desc.getCapHeight();
        }
        if (java.lang.Float.compare(retval, 0) == 0) {
            retval = desc.getAscent();
        }
        if (java.lang.Float.compare(retval, 0) == 0) {
            retval = desc.getXHeight();
            if (retval > 0) {
                retval -= desc.getDescent();
            }
        }
        return retval;
    }
    return 0;
}

