/**
 * Returns the Unicode character sequence for the given glyph name, or null if there isn't any.
 *
 * @param name
 * 		PostScript glyph name
 * @return Unicode character(s), or null.
 */
public java.lang.String toUnicode(java.lang.String name) {
    if (name == null) {
        return null;
    }
    java.lang.String unicode = nameToUnicode.get(name);
    if (unicode != null) {
        return unicode;
    }
    // separate read/write cache for thread safety
    unicode = uniNameToUnicodeCache.get(name);
    if (unicode == null) {
        // test if we have a suffix and if so remove it
        if (name.indexOf('.') > 0) {
            unicode = toUnicode(name.substring(0, name.indexOf('.')));
        } else if (((name.length() == 7) && name.startsWith("uni")) || ((name.length() == 5) && name.startsWith("u"))) {
            // test for Unicode name in the format uniXXXX/uXXXX where X is hex
            int start = (name.length() == 7) ? 3 : 1;
            try {
                int codePoint = java.lang.Integer.parseInt(name, start, start + 4, 16);
                if ((codePoint > 0xd7ff) && (codePoint < 0xe000)) {
                    org.apache.pdfbox.pdmodel.font.encoding.GlyphList.LOG.warn("Unicode character name with disallowed code area: {}", name);
                } else {
                    unicode = java.lang.String.valueOf(((char) (codePoint)));
                }
            } catch (java.lang.NumberFormatException nfe) {
                org.apache.pdfbox.pdmodel.font.encoding.GlyphList.LOG.warn("Not a number in Unicode character name: {}", name);
            }
        }
        if (unicode != null) {
            // null value not allowed in ConcurrentHashMap
            uniNameToUnicodeCache.put(name, unicode);
        }
    }
    return unicode;
}

