 *
 * @return RGB
 * @throws IOException
 * 		if the color conversion fails
 * @throws UnsupportedOperationException
 * 		if this color value is a pattern.
 */
public int toRGB() throws java.io.IOException {
    float[] floats = colorSpace.toRGB(components);
    int r = java.lang.Math.round(floats[0] * 255);
    int g = java.lang.Math.round(floats[1] * 255);
    int b = java.lang.Math.round(floats[2] * 255);
