@java.lang.Override
public float[] toRGB(float[] value) {
    if (value.length != 1) {
        throw new java.lang.IllegalArgumentException("Indexed color spaces must have one color value");
    }
    // scale and clamp input value
    int index = java.lang.Math.round(value[0]);
    index = java.lang.Math.max(index, 0);
    index = java.lang.Math.min(index, actualMaxIndex);
    // lookup rgb
    int[] rgb = rgbColorTable[index];
    return new float[]{ rgb[0] / 255.0F, rgb[1] / 255.0F, rgb[2] / 255.0F };
}

