// WARNING: this method is performance sensitive, modify with care!
// 
@java.lang.Override
public java.awt.image.BufferedImage toRGBImage(java.awt.image.WritableRaster raster) throws java.io.IOException {
    int width = raster.getWidth();
    int height = raster.getHeight();
    java.awt.image.BufferedImage rgbImage = new java.awt.image.BufferedImage(width, height, java.awt.image.BufferedImage.TYPE_INT_RGB);
    java.awt.image.WritableRaster rgbRaster = rgbImage.getRaster();
    org.apache.pdfbox.pdmodel.common.PDRange aRange = getARange();
    org.apache.pdfbox.pdmodel.common.PDRange bRange = getBRange();
    float minA = aRange.getMin();
    float maxA = aRange.getMax();
    float minB = bRange.getMin();
    float maxB = bRange.getMax();
    float deltaA = maxA - minA;
    float deltaB = maxB - minB;
    // always three components: ABC
    float[] abc = new float[3];
    for (int y = 0; y < height; y++) {
        for (int x = 0; x < width; x++) {
            raster.getPixel(x, y, abc);
            // 0..255 -> 0..1
            abc[0] /= 255;
            abc[1] /= 255;
            abc[2] /= 255;
            // scale to range
            abc[0] *= 100;
            abc[1] = minA + (abc[1] * deltaA);
            abc[2] = minB + (abc[2] * deltaB);
            float[] rgb = toRGB(abc);
            // 0..1 -> 0..255
            rgb[0] *= 255;
            rgb[1] *= 255;
            rgb[2] *= 255;
            rgbRaster.setPixel(x, y, rgb);
        }
    }
    return rgbImage;
}

