@java.lang.Override
public java.awt.image.BufferedImage toRGBImage(java.awt.image.WritableRaster raster) throws java.io.IOException {
    if (alternateColorSpace instanceof org.apache.pdfbox.pdmodel.graphics.color.PDLab) {
        // PDFBOX-3622 - regular converter fails for Lab colorspaces
        return toRGBImage2(raster);
    } else if (alternateColorSpace instanceof org.apache.pdfbox.pdmodel.graphics.color.PDICCBased) {
        // PDFBOX-5778 - same problem if Lab-based ICC colorspace
        org.apache.pdfbox.pdmodel.graphics.color.PDColorSpace iccAlternateColorSpace = ((org.apache.pdfbox.pdmodel.graphics.color.PDICCBased) (alternateColorSpace)).getAlternateColorSpace();
        if (iccAlternateColorSpace instanceof org.apache.pdfbox.pdmodel.graphics.color.PDLab) {
            return toRGBImage2(raster);
        }
    }
    int numAltComponents = alternateColorSpace.getNumberOfComponents();
    // use the tint transform to convert the sample into
    // the alternate color space (this is usually 1:many)
    java.awt.image.WritableRaster altRaster = java.awt.image.Raster.createBandedRaster(java.awt.image.DataBuffer.TYPE_BYTE, raster.getWidth(), raster.getHeight(), numAltComponents, new java.awt.Point(0, 0));
    int width = raster.getWidth();
    int height = raster.getHeight();
    float[] samples = new float[1];
    java.util.Map<java.lang.Integer, int[]> calculatedValues = new java.util.HashMap<>();
    java.lang.Integer hash;
    for (int y = 0; y < height; y++) {
        for (int x = 0; x < width; x++) {
            raster.getPixel(x, y, samples);
            hash = java.lang.Float.floatToIntBits(samples[0]);
            int[] alt = calculatedValues.get(hash);
            if (alt == null) {
                alt = new int[numAltComponents];
                tintTransform(samples, alt);
                calculatedValues.put(hash, alt);
            }
            altRaster.setPixel(x, y, alt);
        }
    }
    // convert the alternate color space to RGB
    return alternateColorSpace.toRGBImage(altRaster);
}

