/**
 * (Optional; PDF 1.7) specifies an acceptable key-usage extension that must be presennt in the
 * signing certificate for works like {@link #setKeyUsage(List)} but takes only one string
 *
 * @param keyUsageExtension
 * 		String that consist only of {0, 1, X}
 */
public void addKeyUsage(java.lang.String keyUsageExtension) {
    java.lang.String allowedChars = "01X";
    for (int c = 0; c < keyUsageExtension.length(); c++) {
        if (allowedChars.indexOf(keyUsageExtension.charAt(c)) == (-1)) {
            throw new java.lang.IllegalArgumentException("characters can only be 0, 1, X");
        }
    }
    org.apache.pdfbox.cos.COSArray array = dictionary.getCOSArray(org.apache.pdfbox.cos.COSName.KEY_USAGE);
    if (array == null) {
