/**
 * Returns list of maps that contains subject distinguished names like [(cn: John Doe, o: Doe), (cn: John Smith)]
 * both keys are typically of the form 'cn', 'o', 'email', '2.5.4.43'; and values are text strings.
 *
 * @return list maps that contains subject distinguished names
 */
public java.util.List<java.util.Map<java.lang.String, java.lang.String>> getSubjectDN() {
    org.apache.pdfbox.cos.COSArray cosArray = dictionary.getCOSArray(org.apache.pdfbox.cos.COSName.SUBJECT_DN);
    if (cosArray != null) {
        java.util.List<? extends org.apache.pdfbox.cos.COSBase> subjectDNList = cosArray.toList();
        java.util.List<java.util.Map<java.lang.String, java.lang.String>> result = new java.util.LinkedList<>();
        for (org.apache.pdfbox.cos.COSBase subjectDNItem : subjectDNList) {
            if (subjectDNItem instanceof org.apache.pdfbox.cos.COSDictionary) {
                org.apache.pdfbox.cos.COSDictionary subjectDNItemDict = ((org.apache.pdfbox.cos.COSDictionary) (subjectDNItem));
                java.util.Map<java.lang.String, java.lang.String> subjectDNMap = new java.util.HashMap<>();
                for (org.apache.pdfbox.cos.COSName key : subjectDNItemDict.keySet()) {
                    subjectDNMap.put(key.getName(), subjectDNItemDict.getString(key));
                }
                result.add(subjectDNMap);
            }
        }
        return result;
    }
    return null;
}

