/**
 * Will return the embedded signature between the byterange gap.
 *
 * @param pdfFile
 * 		The signed pdf file as byte array
 * @return a byte array containing the signature
 * @throws IOException
 * 		if the pdfFile can't be read
 * @throws IndexOutOfBoundsException
 * 		if the byterange array is not long enough
 */
public byte[] getContents(byte[] pdfFile) throws java.io.IOException {
    int[] byteRange = getByteRange();
    int begin = (byteRange[0] + byteRange[1]) + 1;
    int len = (byteRange[2] - begin) - 1;
    return getConvertedContents(new java.io.ByteArrayInputStream(pdfFile, begin, len));
}

