    org.apache.pdfbox.pdmodel.interactive.digitalsignature.visible.PDFTemplateBuilder builder = new org.apache.pdfbox.pdmodel.interactive.digitalsignature.visible.PDVisibleSigBuilder();
    org.apache.pdfbox.pdmodel.interactive.digitalsignature.visible.PDFTemplateCreator creator = new org.apache.pdfbox.pdmodel.interactive.digitalsignature.visible.PDFTemplateCreator(builder);
    setVisibleSignature(creator.buildPDF(getPdVisibleSignature()));
}

