/**
 * Adjust signature for page rotation. This is optional, call this after all x and y coordinates
 * have been set if you want the signature to be positioned regardless of page orientation.
 *
 * @return Visible Signature Configuration Object
 */
public org.apache.pdfbox.pdmodel.interactive.digitalsignature.visible.PDVisibleSignDesigner adjustForRotation() {
    switch (rotation) {
        case 90 :
            // https://stackoverflow.com/a/34359956/535646
            float temp = yAxis;
            yAxis = (pageHeight - xAxis) - imageWidth;
            xAxis = temp;
            affineTransform = new java.awt.geom.AffineTransform(0, imageHeight / imageWidth, (-imageWidth) / imageHeight, 0, imageWidth, 0);
            temp = imageHeight;
            imageHeight = imageWidth;
            imageWidth = temp;
            break;
        case 180 :
            float newX = (pageWidth - xAxis) - imageWidth;
            float newY = (pageHeight - yAxis) - imageHeight;
            xAxis = newX;
            yAxis = newY;
            affineTransform = new java.awt.geom.AffineTransform(-1, 0, 0, -1, imageWidth, imageHeight);
            break;
        case 270 :
            temp = xAxis;
