 *
 * <p>Off is the default value which will also be returned if the
 * value hasn't been set at all.
 *
 * @return A non-null string.
 */
public java.lang.String getValue() {
    org.apache.pdfbox.cos.COSBase value = getInheritableAttribute(org.apache.pdfbox.cos.COSName.V);
    if (value instanceof org.apache.pdfbox.cos.COSName) {
        java.lang.String stringValue = ((org.apache.pdfbox.cos.COSName) (value)).getName();
        java.util.List<java.lang.String> exportValues = getExportValues();
        if (!exportValues.isEmpty()) {
            try {
                int idx = java.lang.Integer.parseInt(stringValue, 10);
                if ((idx >= 0) && (idx < exportValues.size())) {
                    return exportValues.get(idx);
                }
            } catch (java.lang.NumberFormatException nfe) {
                return stringValue;
            }
        }
        return stringValue;
    } else {
