    java.util.List<java.lang.String> exportValues = getExportValues();
    java.util.List<java.lang.String> selectedExportValues = new java.util.ArrayList<>();
    if (exportValues.isEmpty()) {
        selectedExportValues.add(getValue());
        return selectedExportValues;
    } else {
        java.lang.String fieldValue = getValue();
        int idx = 0;
        for (java.lang.String onValue : getOnValues()) {
            if (onValue.compareTo(fieldValue) == 0) {
                selectedExportValues.add(exportValues.get(idx));
