    int idx = 0;
    for (org.apache.pdfbox.pdmodel.interactive.annotation.PDAnnotationWidget widget : getWidgets()) {
        if (!org.apache.pdfbox.cos.COSName.Off.equals(widget.getAppearanceState())) {
