@java.lang.Override
public void importFDF(org.apache.pdfbox.pdmodel.fdf.FDFField fdfField) throws java.io.IOException {
    super.importFDF(fdfField);
    java.lang.Integer f = fdfField.getWidgetFieldFlags();
    for (org.apache.pdfbox.pdmodel.interactive.annotation.PDAnnotationWidget widget : getWidgets()) {
        if (f != null) {
            widget.setAnnotationFlags(f);
        } else {
            // these are supposed to be ignored if the F is set.
            java.lang.Integer setF = fdfField.getSetWidgetFieldFlags();
            int annotFlags = widget.getAnnotationFlags();
            if (setF != null) {
                annotFlags = annotFlags | setF;
                widget.setAnnotationFlags(annotFlags);
            }
            java.lang.Integer clrF = fdfField.getClearWidgetFieldFlags();
            if (clrF != null) {
                // we have to clear the bits of the document fields for every bit that is
                // set in this field.
                // 
                // Example:
                // docF = 1011
                // clrF = 1101
                // clrFValue = 0010;
                // newValue = 1011 & 0010 which is 0010
                int clrFValue = clrF;
                clrFValue ^= 0xffffffffL;
                annotFlags = annotFlags & clrFValue;
                widget.setAnnotationFlags(annotFlags);
            }
        }
    }
}

