/**
 * {@inheritDoc }
 *
 * Returns the actual physical size of the pages in the PDF file. May not fit the local printer.
 */
@java.lang.Override
public java.awt.print.PageFormat getPageFormat(int pageIndex) {
    org.apache.pdfbox.pdmodel.PDPage page = document.getPage(pageIndex);
    org.apache.pdfbox.pdmodel.common.PDRectangle mediaBox = org.apache.pdfbox.printing.PDFPrintable.getRotatedMediaBox(page);
    org.apache.pdfbox.pdmodel.common.PDRectangle cropBox = org.apache.pdfbox.printing.PDFPrintable.getRotatedCropBox(page);
    // Java does not seem to understand landscape paper sizes, i.e. where width > height, it
    // always crops the imageable area as if the page were in portrait. I suspect that this is
    // a JDK bug but it might be by design, see PDFBOX-2922.
    // 
    // As a workaround, we normalise all Page(s) to be portrait, then flag them as landscape in
    // the PageFormat.
    java.awt.print.Paper paper;
    boolean isLandscape;
    if (mediaBox.getWidth() > mediaBox.getHeight()) {
        // rotate
        paper = new java.awt.print.Paper();
        paper.setSize(mediaBox.getHeight(), mediaBox.getWidth());
        paper.setImageableArea(cropBox.getLowerLeftY(), cropBox.getLowerLeftX(), cropBox.getHeight(), cropBox.getWidth());
        isLandscape = true;
    } else {
        paper = new java.awt.print.Paper();
        paper.setSize(mediaBox.getWidth(), mediaBox.getHeight());
        paper.setImageableArea(cropBox.getLowerLeftX(), cropBox.getLowerLeftY(), cropBox.getWidth(), cropBox.getHeight());
        isLandscape = false;
    }
    java.awt.print.PageFormat format = new java.awt.print.PageFormat();
    format.setPaper(paper);
    // auto portrait/landscape
    switch (orientation) {
        case AUTO :
            format.setOrientation(isLandscape ? java.awt.print.PageFormat.LANDSCAPE : java.awt.print.PageFormat.PORTRAIT);
            break;
        case LANDSCAPE :
            format.setOrientation(java.awt.print.PageFormat.LANDSCAPE);
            break;
        case REVERSE_LANDSCAPE :
            format.setOrientation(java.awt.print.PageFormat.REVERSE_LANDSCAPE);
            break;
        case PORTRAIT :
            format.setOrientation(java.awt.print.PageFormat.PORTRAIT);
            break;
        default :
            break;
    }
    return format;
}

