/**
 * Determine if this TextPosition perfectly contains another (i.e. the other TextPosition
 * overlaps 100% with this one and fits entirely inside its bounding box when they are rendered
 * on top of each other).
 *
 * @param tp2
 * 		The other TestPosition to compare against
 * @return True if tp2 is contained completely inside the bounding box of this text.
 */
public boolean completelyContains(org.apache.pdfbox.text.TextPosition tp2) {
    // Note: (0, 0) is in the upper left and y-coordinate is top of TextPosition
    // +---thisTop------------+
    // |    +--tp2Top---+     |
    // |    |           |     |
    // thisLeft |       tp2Right  |
    // | tp2Left        | thisRight
    // |    |           |     |
    // |    +-tp2Bottom-+     |
    // +---------thisBottom---+
    float thisLeft = getXDirAdj();
    float thisWidth = getWidthDirAdj();
    float thisRight = thisLeft + thisWidth;
    float tp2Left = tp2.getXDirAdj();
    float tp2Width = tp2.getWidthDirAdj();
    float tp2Right = tp2Left + tp2Width;
    if ((thisLeft > tp2Left) || (tp2Right > thisRight)) {
        return false;
    }
    float thisTop = getYDirAdj();
    float thisHeight = getHeightDir();
    float thisBottom = thisTop + thisHeight;
    float tp2Top = tp2.getYDirAdj();
    float tp2Height = tp2.getHeightDir();
    float tp2Bottom = tp2Top + tp2Height;
    if ((thisTop > tp2Top) || (tp2Bottom > thisBottom)) {
        return false;
    }
    return true;
}

/**
 * Determine if this TextPosition logically contains another (i.e. they overlap and should be
 * rendered on top of each other).
 *
 * @param tp2
 * 		The other TestPosition to compare against
 * @return True if tp2 is contained in the bounding box of this text.
 */
public boolean contains(org.apache.pdfbox.text.TextPosition tp2) {
    double thisXstart = getXDirAdj();
    double thisWidth = getWidthDirAdj();
    double thisXend = thisXstart + thisWidth;
    double tp2Xstart = tp2.getXDirAdj();
    double tp2Xend = tp2Xstart + tp2.getWidthDirAdj();
    // no X overlap at all so return as soon as possible
    if ((tp2Xend <= thisXstart) || (tp2Xstart >= thisXend)) {
        return false;
    }
    // no Y overlap at all so return as soon as possible. Note: 0.0 is in the upper left and
    // y-coordinate is top of TextPosition
    double thisYstart = getYDirAdj();
    double tp2Ystart = tp2.getYDirAdj();
    if (((tp2Ystart + tp2.getHeightDir()) < thisYstart) || (tp2Ystart > (thisYstart + getHeightDir()))) {
        return false;
    } else if ((tp2Xstart > thisXstart) && (tp2Xend > thisXend)) {
        double overlap = thisXend - tp2Xstart;
        double overlapPercent = overlap / thisWidth;
        return overlapPercent > 0.15;
    } else if ((tp2Xstart < thisXstart) && (tp2Xend < thisXend)) {
        double overlap = tp2Xend - thisXstart;
        double overlapPercent = overlap / thisWidth;
        return overlapPercent > 0.15;
    }
    return true;
}

