/**
 * Return the direction/orientation of the string in this object based on its text matrix. Only
 * angles of 0, 90, 180, or 270 are supported. To get other angles, use this code:
 * <pre>
 * TextPosition text = ...
 * Matrix m = text.getTextMatrix().clone();
 * m.concatenate(text.getFont().getFontMatrix());
 * int angle = (int) Math.round(Math.toDegrees(Math.atan2(m.getShearY(), m.getScaleY())));
 * </pre>
 *
 * @return The direction of the text (0, 90, 180, or 270).
 */
public float getDir() {
    if (direction < 0) {
        float a = textMatrix.getScaleY();
        float b = textMatrix.getShearY();
        float c = textMatrix.getShearX();
        float d = textMatrix.getScaleX();
        // 12 0   left to right
        // 0 12
        if ((((a > 0) && (java.lang.Math.abs(b) < d)) && (java.lang.Math.abs(c) < a)) && (d > 0)) {
            direction = 0;
        } else if ((((a < 0) && (java.lang.Math.abs(b) < java.lang.Math.abs(d))) && (java.lang.Math.abs(c) < java.lang.Math.abs(a))) && (d < 0)) {
            direction = 180;
        } else if ((((java.lang.Math.abs(a) < java.lang.Math.abs(c)) && (b > 0)) && (c < 0)) && (java.lang.Math.abs(d) < b)) {
            direction = 90;
        } else if ((((java.lang.Math.abs(a) < c) && (b < 0)) && (c > 0)) && (java.lang.Math.abs(d) < java.lang.Math.abs(b))) {
            direction = 270;
        } else {
            direction = 0;
        }
    }
    return direction;
}

/**
 * Same as {@link #getUnicode()} except that returned text is ensured to be
 * visually ordered (i.e. same order you would see them displayed on screen when
 * looking from left to right). This is important for Arabic/Hebrew where several
 * unicode characters can be composed in one glyph with logical order (the order
 * in which it would be normally typed from right to left).
 *
 * @return The string on the screen in visual order.
 */
public java.lang.String getVisuallyOrderedUnicode() {
    final java.lang.String text = getUnicode();
    final int length = text.length();
    int nextIndex;
    for (int index = 0; index < length; index = nextIndex) {
        int codePoint = text.codePointAt(index);
        nextIndex = index + java.lang.Character.charCount(codePoint);
        byte directionality = java.lang.Character.getDirectionality(codePoint);
        if (((directionality == java.lang.Character.DIRECTIONALITY_RIGHT_TO_LEFT_ARABIC) || (directionality == java.lang.Character.DIRECTIONALITY_RIGHT_TO_LEFT)) && // Even if the directionality is right to left, still there is no need to
        // reverse a single code-point
        ((index != 0) || (nextIndex < length))) {
            return new java.lang.StringBuilder(text).reverse().toString();
        }
    }
    return text;
}

/**
 * This will get the y position of the text, adjusted so that 0,0 is upper left and it is
 * adjusted based on the text direction.
 * This method ignores the page rotation but takes the
 * text rotation and adjusts the coordinates to awt. This is useful when doing text extraction,
 * to compare the glyph positions when imagining these to be horizontal. See also
 * <a href="https://stackoverflow.com/questions/57067372/">this answer by Michael Klink</a> for
 * further details and
 * <a href="https://issues.apache.org/jira/browse/PDFBOX-4597">PDFBOX-4597</a> for a sample
 * file.
 *
 * @return The adjusted y coordinate of the character.
 */
public float getYDirAdj() {
    float dir = getDir();
    // some PDFBox code assumes that the 0,0 point is in upper left, not lower left
    if ((java.lang.Float.compare(dir, 0) == 0) || (java.lang.Float.compare(dir, 180) == 0)) {
        return pageHeight - getYLowerLeftRot(dir);
    } else {
        return pageWidth - getYLowerLeftRot(dir);
    }
}

@java.lang.Override
public int hashCode() {
    int result = (textMatrix != null) ? textMatrix.hashCode() : 0;
    result = (31 * result) + java.lang.Float.floatToIntBits(endX);
    result = (31 * result) + java.lang.Float.floatToIntBits(endY);
    result = (31 * result) + java.lang.Float.floatToIntBits(maxHeight);
    result = (31 * result) + rotation;
    result = (31 * result) + java.lang.Float.floatToIntBits(x);
    result = (31 * result) + java.lang.Float.floatToIntBits(y);
    result = (31 * result) + java.lang.Float.floatToIntBits(pageHeight);
    result = (31 * result) + java.lang.Float.floatToIntBits(pageWidth);
    result = (31 * result) + java.lang.Float.floatToIntBits(widthOfSpace);
    result = (31 * result) + java.util.Arrays.hashCode(charCodes);
    result = (31 * result) + (font != null ? font.hashCode() : 0);
    result = (31 * result) + java.lang.Float.floatToIntBits(fontSize);
    result = (31 * result) + fontSizePt;
    return result;
}

/**
 *
 * @return True if the current character is a diacritic char.
 */
public boolean isDiacritic() {
    java.lang.String text = this.getUnicode();
    if (text.length() != 1) {
        return false;
    }
    if ("ー".equals(text)) {
        // PDFBOX-3833: ー is not a real diacritic like ¨ or ˆ, it just changes the
        // pronunciation of the previous sound, and is printed after the previous glyph
        // http://www.japanesewithanime.com/2017/04/prolonged-sound-mark.html
        // Ignoring it as diacritic avoids trouble if it slightly overlaps with the next glyph.
        return false;
    }
    int type = java.lang.Character.getType(text.charAt(0));
    return ((type == java.lang.Character.NON_SPACING_MARK) || (type == java.lang.Character.MODIFIER_SYMBOL)) || (type == java.lang.Character.MODIFIER_LETTER);
}

@java.lang.Override
public int compare(org.apache.pdfbox.text.TextPosition pos1, org.apache.pdfbox.text.TextPosition pos2) {
    // only compare text that is in the same direction
    int cmp1 = java.lang.Float.compare(pos1.getDir(), pos2.getDir());
    if (cmp1 != 0) {
        return cmp1;
    }
    // get the text direction adjusted coordinates
    float x1 = pos1.getXDirAdj();
    float x2 = pos2.getXDirAdj();
    float pos1YBottom = pos1.getYDirAdj();
    float pos2YBottom = pos2.getYDirAdj();
    // note that the coordinates have been adjusted so 0,0 is in upper left
    float pos1YTop = pos1YBottom - pos1.getHeightDir();
    float pos2YTop = pos2YBottom - pos2.getHeightDir();
    float yDifference = java.lang.Math.abs(pos1YBottom - pos2YBottom);
    // we will do a simple tolerance comparison
    if (((yDifference < 0.1) || ((pos2YBottom >= pos1YTop) && (pos2YBottom <= pos1YBottom))) || ((pos1YBottom >= pos2YTop) && (pos1YBottom <= pos2YBottom))) {
        return java.lang.Float.compare(x1, x2);
    } else if (pos1YBottom < pos2YBottom) {
        return -1;
    } else {
        return 1;
    }
}

