/**
 * Create a schema that corresponding to this factory and add it to metadata
 *
 * @param metadata
 * 		Metadata to attach the Schema created
 * @param prefix
 * 		The namespace prefix (optional)
 * @return the schema created and added to metadata
 * @throws XmpSchemaException
 * 		When Instancing specified Object Schema failed
 */
public org.apache.xmpbox.schema.XMPSchema createXMPSchema(org.apache.xmpbox.XMPMetadata metadata, java.lang.String prefix) throws org.apache.xmpbox.schema.XmpSchemaException {
    org.apache.xmpbox.schema.XMPSchema schema;
    java.lang.Class<?>[] argsClass;
    java.lang.Object[] schemaArgs;
    if (schemaClass == org.apache.xmpbox.schema.XMPSchema.class) {
        argsClass = new java.lang.Class[]{ org.apache.xmpbox.XMPMetadata.class, java.lang.String.class, java.lang.String.class };
        schemaArgs = new java.lang.Object[]{ metadata, namespace, prefix };
    } else if ((prefix != null) && (!prefix.isEmpty())) {
        argsClass = new java.lang.Class[]{ org.apache.xmpbox.XMPMetadata.class, java.lang.String.class };
        schemaArgs = new java.lang.Object[]{ metadata, prefix };
    } else {
        argsClass = new java.lang.Class[]{ org.apache.xmpbox.XMPMetadata.class };
        schemaArgs = new java.lang.Object[]{ metadata };
    }
    try {
        schema = schemaClass.getDeclaredConstructor(argsClass).newInstance(schemaArgs);
        metadata.addSchema(schema);
        return schema;
    } catch (java.lang.Exception e) {
        throw new org.apache.xmpbox.schema.XmpSchemaException("Cannot instantiate specified object schema", e);
    }
}

/**
 * Add a property to the current structure
 *
 * @param obj
 * 		the property to add
 */
public final void addProperty(org.apache.xmpbox.type.AbstractField obj) {
    // https://www.adobe.com/content/dam/Adobe/en/devnet/xmp/pdfs/cs6/XMPSpecificationPart1.pdf
    // "Each property name in an XMP packet shall be unique within that packet"
    // "Multiple values are represented using an XMP array value"
    // "The nested element's element content shall consist of zero or more rdf:li elements,
    // one for each item in the array"
    // thus delete existing elements of a property, except for arrays ("li")
    if (!(this instanceof org.apache.xmpbox.type.ArrayProperty)) {
        container.removePropertiesByName(obj.getPropertyName());
    }
    container.addProperty(obj);
}

