}

/**
 * Check if a XMPFieldObject is in the complex property
 *
 * @param property
 * 		The property to check
 * @return True if property is present in this container
 */
public boolean containsProperty(org.apache.xmpbox.type.AbstractField property) {
    java.util.Iterator<org.apache.xmpbox.type.AbstractField> it = getAllProperties().iterator();
    org.apache.xmpbox.type.AbstractField tmp;
    while (it.hasNext()) {
        tmp = it.next();
        if (isSameProperty(tmp, property)) {
            return true;
        }
    } 
    return false;
}

