    }
}

/**
 * Check if two properties are equal.
 *
 * @param prop1
 * 		First property
 * @param prop2
 * 		Second property
 * @return True if these properties are equal.
 */
public boolean isSameProperty(org.apache.xmpbox.type.AbstractField prop1, org.apache.xmpbox.type.AbstractField prop2) {
    if (prop1.getClass().equals(prop2.getClass())) {
        java.lang.String pn1 = prop1.getPropertyName();
        java.lang.String pn2 = prop2.getPropertyName();
        if (pn1 == null) {
            return pn2 == null;
        } else if (pn1.equals(pn2)) {
            return prop1.equals(prop2);
        }
    }
    return false;
}

