/**
 * Get a property description based on namespace and field name. Both are needed because there
 * can be several property descriptions for one namespace.
 *
 * @param namespace
 * @param pdfaFieldName
 * @return  */
public org.apache.xmpbox.type.PropertiesDescription getDefinedDescriptionByNamespace(java.lang.String namespace, java.lang.String pdfaFieldName) {
    java.util.List<org.apache.xmpbox.type.PropertiesDescription> propDescList = definedStructuredNamespaces2.get(namespace);
    for (org.apache.xmpbox.type.PropertiesDescription propDesc : propDescList) {
        // check whether one of these field names matches
        if (propDesc.getPropertiesNames().contains(pdfaFieldName)) {
            return propDesc;
        }
    }
    return null;
}

/**
 * Give type of specified property in specified schema (given by its namespaceURI)
 *
 * @param qName
 * 		the property Qualified Name
 * @param parentTypeName
 * 		the type name of the parent, or null if not known. This is intended to
 * 		help when the field name is in several types, e.g. "Values" in exif.
 * @return Property type declared for namespace specified, null if unknown
 * @throws org.apache.xmpbox.type.BadFieldValueException
 * 		if the name of a type was not found.
 */
public org.apache.xmpbox.type.PropertyType getSpecifiedPropertyType(javax.xml.namespace.QName qName, java.lang.String parentTypeName) throws org.apache.xmpbox.type.BadFieldValueException {
    // PDFBOX-6133: the method was rewritten because of photoshop and exif,
    // because these namespaces exist as a schema and as a type
    // "factory" is checked in the non-schema part to keep the pre PDFBOX-6133 behavior
    org.apache.xmpbox.schema.XMPSchemaFactory factory = getSchemaFactory(qName.getNamespaceURI());
    if (factory != null) {
        // found in schema
        org.apache.xmpbox.type.PropertyType propertyType = factory.getPropertyType(qName.getLocalPart());
        if (propertyType != null) {
            return propertyType;
        }
    }
    // try in structured
    java.util.List<org.apache.xmpbox.type.Types> list = structuredNamespaces2.get(qName.getNamespaceURI());
    if (list != null) {
        if (list.size() == 1) {
            org.apache.xmpbox.type.Types st = list.get(0);
            org.apache.xmpbox.type.PropertiesDescription propDesc = structuredMappings.get(st);
            if ((factory == null) || propDesc.getPropertiesNames().contains(qName.getLocalPart())) {
                return org.apache.xmpbox.type.TypeMapping.createPropertyType(st, org.apache.xmpbox.type.Cardinality.Simple);
            }
            return null;
        }
        if (list.size() > 1) {
            for (org.apache.xmpbox.type.Types type : list) {
                if (type.name().equals(parentTypeName)) {
                    return org.apache.xmpbox.type.TypeMapping.createPropertyType(type, org.apache.xmpbox.type.Cardinality.Simple);
                }
            }
            for (org.apache.xmpbox.type.Types type : list) {
                org.apache.xmpbox.type.PropertiesDescription propDesc = structuredMappings.get(type);
                if (propDesc.getPropertiesNames().contains(qName.getLocalPart())) {
                    return org.apache.xmpbox.type.TypeMapping.createPropertyType(type, org.apache.xmpbox.type.Cardinality.Simple);
                }
            }
        }
        return null;
    }
    // try in defined
    if (!definedStructuredNamespaces2.containsKey(qName.getNamespaceURI())) {
        // not found
        if (factory != null) {
            return null;// pre PDFBOX-6133 behavior

        }
        throw new org.apache.xmpbox.type.BadFieldValueException("No descriptor found for " + qName);
    } else {
        return org.apache.xmpbox.type.TypeMapping.createPropertyType(org.apache.xmpbox.type.Types.DefinedType, org.apache.xmpbox.type.Cardinality.Simple);
    }
}

public org.apache.xmpbox.type.PropertiesDescription initializePropMapping(java.lang.Class<?> classSchem) {
    org.apache.xmpbox.type.PropertiesDescription propMap = new org.apache.xmpbox.type.PropertiesDescription();
    java.lang.reflect.Field[] fields = classSchem.getFields();
    java.lang.String propName = null;
    for (java.lang.reflect.Field field : fields) {
        if (field.isAnnotationPresent(org.apache.xmpbox.type.PropertyType.class)) {
            try {
                propName = ((java.lang.String) (field.get(propName)));
            } catch (java.lang.Exception e) {
                throw new java.lang.IllegalArgumentException("couldn't read one type declaration, please check accessibility and declaration of fields annotated in " + classSchem.getName(), e);
            }
            org.apache.xmpbox.type.PropertyType propType = field.getAnnotation(org.apache.xmpbox.type.PropertyType.class);
            propMap.addNewProperty(propName, propType);
        }
    }
    return propMap;
}

public org.apache.xmpbox.type.AbstractSimpleProperty instanciateSimpleField(java.lang.Class<?> clz, java.lang.String nsuri, java.lang.String prefix, java.lang.String propertyName, java.lang.Object value) {
    org.apache.xmpbox.type.PropertiesDescription pm = initializePropMapping(clz);
    org.apache.xmpbox.type.PropertyType simpleType = pm.getPropertyType(propertyName);
    org.apache.xmpbox.type.Types type = simpleType.type();
    return instanciateSimpleProperty(nsuri, prefix, propertyName, value, type);
}

public org.apache.xmpbox.type.AbstractSimpleProperty instanciateSimpleProperty(java.lang.String nsuri, java.lang.String prefix, java.lang.String name, java.lang.Object value, org.apache.xmpbox.type.Types type) {
    // constructor parameters
    java.lang.Object[] params = new java.lang.Object[]{ metadata, nsuri, prefix, name, value };
    // type
    java.lang.Class<? extends org.apache.xmpbox.type.AbstractSimpleProperty> clz = type.getImplementingClass().asSubclass(org.apache.xmpbox.type.AbstractSimpleProperty.class);
    try {
        java.lang.reflect.Constructor<? extends org.apache.xmpbox.type.AbstractSimpleProperty> cons = clz.getDeclaredConstructor(org.apache.xmpbox.type.TypeMapping.SIMPLEPROPERTYCONSTPARAMS);
        return cons.newInstance(params);
    } catch (java.lang.NoSuchMethodError | java.lang.IllegalArgumentException | java.lang.InstantiationException | java.lang.IllegalAccessException | java.lang.reflect.InvocationTargetException | java.lang.SecurityException | java.lang.NoSuchMethodException e) {
        throw new java.lang.IllegalArgumentException(((("Failed to instantiate " + clz.getSimpleName()) + " property with value '") + value) + "'", e);
    }
}

public org.apache.xmpbox.XMPMetadata parse(byte[] xmp) throws org.apache.xmpbox.xml.XmpParsingException {
    java.io.ByteArrayInputStream input = new java.io.ByteArrayInputStream(xmp);
    return parse(input);
}

public org.apache.xmpbox.XMPMetadata parse(java.io.InputStream input) throws org.apache.xmpbox.xml.XmpParsingException {
    org.w3c.dom.Document document = null;
    try {
        // prevents validation messages polluting the console
        dBuilder.setErrorHandler(null);
        document = dBuilder.parse(input);
    } catch (org.xml.sax.SAXException | java.io.IOException e) {
        throw new org.apache.xmpbox.xml.XmpParsingException(org.apache.xmpbox.xml.XmpParsingException.ErrorType.Undefined, "Failed to parse: " + e.getMessage(), e);
    }
    org.apache.xmpbox.XMPMetadata xmp = null;
    // Start reading
    removeCommentsAndBlanks(document);
    org.w3c.dom.Node node = document.getFirstChild();
    // expect xpacket processing instruction
    if (!(node instanceof org.w3c.dom.ProcessingInstruction)) {
        if (strictParsing) {
            throw new org.apache.xmpbox.xml.XmpParsingException(org.apache.xmpbox.xml.XmpParsingException.ErrorType.XpacketBadStart, "xmp should start with a processing instruction");
        }
        xmp = org.apache.xmpbox.XMPMetadata.createXMPMetadata(org.apache.xmpbox.XmpConstants.DEFAULT_XPACKET_BEGIN, org.apache.xmpbox.XmpConstants.DEFAULT_XPACKET_ID, org.apache.xmpbox.XmpConstants.DEFAULT_XPACKET_BYTES, org.apache.xmpbox.XmpConstants.DEFAULT_XPACKET_ENCODING);
    } else {
        xmp = parseInitialXpacket(((org.w3c.dom.ProcessingInstruction) (node)));
        node = node.getNextSibling();
    }
    // forget other processing instruction
    while (node instanceof org.w3c.dom.ProcessingInstruction) {
        node = node.getNextSibling();
    } 
    // expect root element
    org.w3c.dom.Element root = null;
    if (!(node instanceof org.w3c.dom.Element)) {
        throw new org.apache.xmpbox.xml.XmpParsingException(org.apache.xmpbox.xml.XmpParsingException.ErrorType.NoRootElement, "xmp should contain a root element");
    } else {
        // use this element as root
        root = ((org.w3c.dom.Element) (node));
        node = node.getNextSibling();
    }
    // expect xpacket end
    if (!(node instanceof org.w3c.dom.ProcessingInstruction)) {
        if (strictParsing) {
            throw new org.apache.xmpbox.xml.XmpParsingException(org.apache.xmpbox.xml.XmpParsingException.ErrorType.XpacketBadEnd, "xmp should end with a processing instruction");
        }
        xmp.setEndXPacket(org.apache.xmpbox.XmpConstants.DEFAULT_XPACKET_END);
    } else {
        parseEndPacket(xmp, ((org.w3c.dom.ProcessingInstruction) (node)));
        node = node.getNextSibling();
    }
    // should be null
    if (node != null) {
        throw new org.apache.xmpbox.xml.XmpParsingException(org.apache.xmpbox.xml.XmpParsingException.ErrorType.XpacketBadEnd, "xmp should end after xpacket end processing instruction");
    }
    // xpacket is OK and there are no more nodes
    // Now, parse the content of root
    nsFinder.push(root);// PDFBOX-6138: push namespaces in root

    org.w3c.dom.Element rdfRdf = findDescriptionsParent(root);
    nsFinder.push(rdfRdf);// PDFBOX-6099: push namespaces in rdf:RDF

    // PDFBOX-6127: look for non standard namespaces (similar to PDFBOX-2378)
    if (!strictParsing) {
        org.w3c.dom.NamedNodeMap nnm = rdfRdf.getAttributes();
        for (int i = 0; i < nnm.getLength(); i++) {
            org.w3c.dom.Attr attr = ((org.w3c.dom.Attr) (nnm.item(i)));
            if (javax.xml.XMLConstants.XMLNS_ATTRIBUTE.equals(attr.getPrefix())) {
                maybeAddNonStandardNamespace(xmp, attr);
            }
        }
    }
    java.util.List<org.w3c.dom.Element> descriptions = org.apache.xmpbox.xml.DomHelper.getElementChildren(rdfRdf);
    for (org.w3c.dom.Element description : descriptions) {
        parseSchemaExtensions(xmp, description);
    }
    // find schema description
    org.apache.xmpbox.xml.PdfaExtensionHelper.populateSchemaMapping(xmp, strictParsing);
    // parse data description
    for (org.w3c.dom.Element description : descriptions) {
        parseDescriptionRoot(xmp, description);
    }
    nsFinder.pop();
    nsFinder.pop();
    return xmp;
}
